import { MarketStat, ServerType, AlbionItem, Language } from '../types';
import { SERVER_URLS, CITIES, ITEM_DATABASE } from '../constants';
import { supabase } from './supabaseClient';

const CACHE_DURATION = 30 * 1000;
const memoryCache = new Map<string, { timestamp: number; data: any }>();

export const getItemImageUrl = (itemId: string, quality: number = 1): string => {
    const cleanId = itemId.split('@')[0]; // Remove encantamento para a imagem base se necessário
    return `https://render.albiononline.com/v1/item/${itemId}.png?quality=${quality}`;
};

export const getRelativeTime = (dateString: string, t: Record<string, string>): string => {
    if (!dateString) return '';
    const date = new Date(dateString);
    if (isNaN(date.getTime())) return '';
    const now = new Date();
    const diffMs = now.getTime() - date.getTime(); 
    const diffMinutes = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMinutes / 60);
    const diffDays = Math.floor(diffHours / 24);
    if (diffMinutes < 1) return `< 1m ${t.ago || 'atrás'}`;
    if (diffMinutes < 60) return `${diffMinutes}m ${t.ago || 'atrás'}`;
    if (diffHours < 24) return `${diffHours}h ${t.ago || 'atrás'}`;
    return `${diffDays}d ${t.ago || 'atrás'}`;
};

// --- BUSCA INTELIGENTE ---

export const searchItems = async (
    searchTerm: string,
    category: string,
    tier: number | 'all',
    limit: number = 50,
    subcategory: string = 'all'
): Promise<AlbionItem[]> => {

    // Se a busca estiver vazia e não houver filtros, retornamos itens populares
    if (!searchTerm && category === 'all' && tier === 'all') {
        return ITEM_DATABASE.slice(0, limit);
    }

    // Tenta primeiro o banco de dados Supabase (se configurado)
    try {
        const results = await searchItemsDirect(searchTerm, category, tier, subcategory, limit);
        if (results.length > 0) return results;
    } catch (err) {
        // Fallback para constantes locais
    }

    // Busca Local Otimizada (Simulando inteligência do Tools4Albion)
    return filterLocalItems(searchTerm, category, tier, subcategory, limit);
};

const filterLocalItems = (searchTerm: string, category: string, tier: number | 'all', subcategory: string = 'all', limit: number) => {
    const query = searchTerm.toLowerCase().trim();
    const words = query.split(/\s+/);

    return ITEM_DATABASE.filter(item => {
        // 1. Filtro de Tier
        if (tier !== 'all' && item.tier !== tier) return false;

        // 2. Filtro de Categoria
        if (category !== 'all' && item.category.toLowerCase() !== category.toLowerCase()) return false;

        // 3. Filtro de Subcategoria
        if (subcategory !== 'all' && item.subcategory?.toLowerCase() !== subcategory.toLowerCase()) return false;

        // 4. Match Inteligente de Nome (Busca em todos os idiomas e no ID)
        if (!query) return true;

        const searchableString = `
            ${item.names.en} 
            ${item.names.pt || ''} 
            ${item.names.es || ''} 
            ${item.id} 
            T${item.tier}
        `.toLowerCase();

        // Deve conter todas as palavras digitadas (ex: "espada t4" busca Espada E Tier 4)
        return words.every(word => searchableString.includes(word));
    })
    .sort((a, b) => {
        // Prioridade 1: Match exato no início do nome em português ou inglês
        const aName = (a.names.pt || a.names.en).toLowerCase();
        const bName = (b.names.pt || b.names.en).toLowerCase();

        if (aName.startsWith(query) && !bName.startsWith(query)) return -1;
        if (!aName.startsWith(query) && bName.startsWith(query)) return 1;

        // Prioridade 2: Tier mais alto primeiro
        return b.tier - a.tier;
    })
    .slice(0, limit);
};

const searchItemsDirect = async (searchTerm: string, category: string, tier: number | 'all', subcategory: string = 'all', limit: number) => {
    try {
        let query = supabase.from('albion_items').select('*').limit(limit);

        if (searchTerm) {
            const searchStr = searchTerm.trim();
            // Busca inteligente no DB usando ILIKE em múltiplas colunas
            query = query.or(`name_pt.ilike.%${searchStr}%,name_en.ilike.%${searchStr}%,id.ilike.%${searchStr}%`);
        }
        if (category !== 'all') query = query.eq('category', category);
        if (subcategory !== 'all') query = query.eq('subcategory', subcategory);
        if (tier !== 'all') query = query.eq('tier', tier);

        const { data, error } = await query;
        if (error || !data) return [];

        return data.map((row: any) => ({
            id: row.id,
            names: { en: row.name_en, pt: row.name_pt || row.name_en, es: row.name_es || row.name_en },
            tier: row.tier,
            category: row.category,
            subcategory: row.subcategory,
        }));
    } catch (e) {
        return [];
    }
};

export const fetchMarketData = async (itemIds: string[], server: ServerType, forceUpdate: boolean = false): Promise<MarketStat[]> => {
    if (itemIds.length === 0) return [];
    const cacheKey = `prices:${server}:${itemIds.slice().sort().join(',')}`;
    const cached = memoryCache.get(cacheKey);
    if (!forceUpdate && cached && (Date.now() - cached.timestamp < CACHE_DURATION)) return cached.data;

    try {
        const baseUrl = SERVER_URLS[server]; 
        const url = `${baseUrl}/${itemIds.join(',')}?locations=Caerleon,Martlock,Thetford,Fort%20Sterling,Lymhurst,Bridgewatch,Brecilien&qualities=1,2,3,4,5`;
        const res = await fetch(url);
        if (!res.ok) throw new Error("API Error");
        const data = await res.json();
        memoryCache.set(cacheKey, { timestamp: Date.now(), data });
        return data;
    } catch (error) {
        return [];
    }
};

export const fetchGoldPrice = async (server: ServerType): Promise<MarketStat | null> => {
    try {
        const baseUrl = SERVER_URLS[server].replace('/prices', '/gold');
        const res = await fetch(`${baseUrl}?count=1`);
        if (!res.ok) return null;
        const data = await res.json();
        if (data.length > 0) {
            return {
                item_id: 'GOLD', city: 'Global', quality: 1,
                sell_price_min: data[0].price, sell_price_min_date: data[0].timestamp,
                buy_price_max: data[0].price, buy_price_max_date: data[0].timestamp
            };
        }
        return null;
    } catch (e) { return null; }
};

export const fetchPriceHistory = async (itemId: string, server: ServerType, period: '24h' | '7d' | '30d'): Promise<any[]> => {
    const rootUrl = SERVER_URLS[server].substring(0, SERVER_URLS[server].lastIndexOf('/prices'));
    const date = new Date();
    if (period === '24h') date.setDate(date.getDate() - 1);
    else if (period === '7d') date.setDate(date.getDate() - 7);
    else date.setDate(date.getDate() - 30);

    const url = `${rootUrl}/charts/${itemId}?date=${date.toISOString().split('T')[0]}&time-scale=${period === '24h' ? 1 : 6}`;
    try {
        const res = await fetch(url);
        const data = await res.json();
        if (data[0]?.data) {
            return data[0].data.timestamps.map((t: any, i: number) => ({
                timestamp: new Date(t).toISOString(),
                price: data[0].data.prices_avg[i]
            }));
        }
        return [];
    } catch (e) { return []; }
};

export const getCraftableItems = async (): Promise<AlbionItem[]> => {
    return ITEM_DATABASE.filter(i => i.craftingRecipe);
};

