import ItemImage from './ItemImage';

interface AdvancedMarketFiltersProps {
  language: string;
  filters: MarketFilters;
  onUpdateFilter: (key: keyof MarketFilters, value: any) => void;
  onReset: () => void;
  onQuickSelect?: (itemId: string) => void;
}

const AdvancedMarketFilters: React.FC<AdvancedMarketFiltersProps> = ({
