    if (filters.category === 'all') return [];
    const category = MARKET_CATEGORIES.find(cat => cat.id === filters.category);
    return category ? category.subcategories : [];
  }, [filters.category]);

  const getTranslation = (key: string) => {
      const translationObj = CATEGORY_TRANSLATIONS[key];
      // @ts-ignore
      if (translationObj) return translationObj[language] || translationObj['en'] || key;
      return key.replace(/_/g, ' '); 
  };

  const handleSearchSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      onUpdateFilter('search', localSearch);
      setShowSuggestions(false);
  };

  return (
    <div ref={containerRef} className="relative z-40">
      <div className="bg-slate-900/95 border border-slate-700 rounded-2xl p-4 mb-2 shadow-2xl backdrop-blur-md transition-all">

        <form onSubmit={handleSearchSubmit} className="flex flex-col md:flex-row gap-3 items-center">

          {/* Input de Busca com Sugestões */}
          <div className="relative flex-1 w-full group">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-500 group-focus-within:text-albion-gold transition-colors" />
              <input 
                  type="text" 
                  value={localSearch}
                  onFocus={() => setShowSuggestions(true)}
                  onChange={(e) => { setLocalSearch(e.target.value); setShowSuggestions(true); }}
                  placeholder={language === 'pt' ? 'Busca inteligente (ex: "espada t6")' : 'Smart search (e.g. "sword t6")'}
                  className="w-full bg-slate-800 border border-slate-700 rounded-xl py-3.5 pl-12 pr-12 text-white font-medium focus:border-albion-gold focus:ring-1 focus:ring-albion-gold/50 focus:outline-none transition-all"
              />
              {localSearch && (
                  <button 
                      type="button"
                      onClick={() => { setLocalSearch(''); onUpdateFilter('search', ''); setSuggestions([]); }}
                      className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 hover:text-white p-1"
                  >
                      <X className="w-5 h-5" />
                  </button>
              )}

              {/* Lista de Sugestões (Dropdown Estilo Tools4Albion) */}
              {showSuggestions && suggestions.length > 0 && (
                  <div className="absolute top-full left-0 right-0 mt-2 bg-slate-800 border border-slate-700 rounded-xl shadow-2xl overflow-hidden animate-fade-in z-50">
                      <div className="p-2 border-b border-slate-700 bg-slate-900/50 flex items-center justify-between">
                          <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest px-2">Sugestões Rápidas</span>
                          <Zap className="w-3 h-3 text-albion-gold" />
                      </div>
                      {suggestions.map(item => (
                          <div 
                              key={item.id}
                              onClick={() => {
                                  if (onQuickSelect) onQuickSelect(item.id);
                                  setLocalSearch(item.names[language as any] || item.names.en);
                                  onUpdateFilter('search', item.names[language as any] || item.names.en);
                                  setShowSuggestions(false);
                              }}
                              className="flex items-center gap-3 p-3 hover:bg-slate-700 cursor-pointer transition-colors border-b border-slate-700/50 last:border-0"
                          >
                              <div className="w-10 h-10 bg-slate-900 rounded-lg flex-shrink-0 border border-slate-600">
                                  <ItemImage itemId={item.id} itemName={item.id} className="w-10 h-10" />
                              </div>
                              <div className="flex-1 min-w-0">
                                  <div className="text-sm font-bold text-slate-200 truncate">{item.names[language as any] || item.names.en}</div>
                                  <div className="text-[10px] text-slate-500 font-bold uppercase">T{item.tier} • {getTranslation(item.category)}</div>
                              </div>
                              <ChevronRight className="w-4 h-4 text-slate-600" />
                          </div>
                      ))}
                  </div>
              )}
          </div>

          <div className="flex gap-2 w-full md:w-auto">
              <button 
                  type="submit"
                  className="flex-1 md:flex-none bg-albion-gold text-albion-dark font-bold px-6 py-3.5 rounded-xl hover:bg-yellow-400 transition-all shadow-lg active:scale-95"
              >
                  {language === 'pt' ? 'Buscar' : 'Search'}
              </button>
              <button 
                  type="button"
                  onClick={() => setExpanded(!expanded)}
                  className={`p-3.5 rounded-xl border transition-all ${expanded ? 'bg-slate-700 border-albion-gold text-white' : 'bg-slate-800 border-slate-700 text-slate-400 hover:text-white'}`}
              >
                  <Filter className="w-6 h-6" />
              </button>
          </div>
        </form>

        {expanded && (
          <div className="mt-6 space-y-6 animate-fade-in border-t border-slate-700 pt-6">
              {/* Tiers */}
              <div>
                  <label className="text-[10px] font-bold text-slate-500 uppercase mb-3 block tracking-widest">Filtrar por Tier</label>
                  <div className="flex flex-wrap gap-2">
                      {TIER_FILTERS.map(tier => (
                          <button
                              key={tier.value}
                              onClick={() => onUpdateFilter('tier', tier.value)}
                              className={`px-4 py-2 rounded-xl text-sm font-bold border transition-all ${
                                  filters.tier === tier.value
                                  ? 'bg-albion-gold text-albion-dark border-albion-gold shadow-lg shadow-albion-gold/20 scale-105'
                                  : 'bg-slate-800 text-slate-400 border-slate-700 hover:border-slate-500'
                              }`}
                          >
                              {tier.label}
                          </button>
                      ))}
                  </div>
              </div>

              {/* Categorias */}
              <div>
                  <label className="text-[10px] font-bold text-slate-500 uppercase mb-3 block tracking-widest">Categorias Principais</label>
                  <div className="flex flex-wrap gap-2">
                      <button
                          onClick={() => onUpdateFilter('category', 'all')}
                          className={`px-4 py-2 rounded-xl text-sm font-bold border transition-all ${
                              filters.category === 'all'
                              ? 'bg-blue-600 text-white border-blue-500 shadow-lg shadow-blue-500/20'
                              : 'bg-slate-800 text-slate-400 border-slate-700 hover:border-slate-500'
                          }`}
                      >
                          Todas
                      </button>
                      {MARKET_CATEGORIES.map(cat => (
                          <button
                              key={cat.id}
                              onClick={() => { onUpdateFilter('category', cat.id); onUpdateFilter('subcategory', 'all'); }}
                              className={`px-4 py-2 rounded-xl text-sm font-bold border transition-all ${
                                  filters.category === cat.id
                                  ? 'bg-blue-600 text-white border-blue-500 shadow-lg shadow-blue-500/20'
                                  : 'bg-slate-800 text-slate-400 border-slate-700 hover:border-slate-500'
                              }`}
                          >
                              {getTranslation(cat.id)}
                          </button>
                      ))}
