              </div>

              {/* Subcategorias */}
              {availableSubcategories.length > 0 && (
                  <div className="animate-fade-in bg-slate-900/50 p-4 rounded-2xl border border-slate-800">
                      <label className="text-[10px] font-bold text-slate-500 uppercase mb-3 block tracking-widest">Subcategorias de {getTranslation(filters.category)}</label>
