                              }`}
                          >
                              Todas
                          </button>
                          {availableSubcategories.map(sub => (
                              <button
                                  key={sub}
                                  onClick={() => onUpdateFilter('subcategory', sub)}
                                  className={`px-3 py-1.5 rounded-lg text-xs font-bold border transition-all ${
                                      filters.subcategory === sub
