);

export default AdvancedMarketFilters;

import React, { useState, useEffect, useMemo } from 'react';
import { getItemImageUrl } from '../services/albionService';
import { Package, Shield, Sword } from 'lucide-react';

interface ItemImageProps {
    itemId: string;
    itemName: string;
    className?: string;
    quality?: number;
}

const ItemImage: React.FC<ItemImageProps> = ({ itemId, itemName, className = "", quality = 1 }) => {
    const [loaded, setLoaded] = useState(false);
    const [error, setError] = useState(false);

    useEffect(() => {
        setLoaded(false);
        setError(false);
    }, [itemId, quality]);

    const imageUrl = getItemImageUrl(itemId, quality);

    // Identificação de Tier para bordas (estilo jogo)
    const tier = useMemo(() => {
        const match = itemId.match(/T(\d+)/);
        return match ? parseInt(match[1]) : 1;
    }, [itemId]);

    // Cores de borda por Tier
    const getTierBorder = (t: number) => {
        if (t >= 8) return 'border-slate-200 shadow-[0_0_8px_rgba(255,255,255,0.2)]'; // Branco/Lendário
        if (t >= 7) return 'border-yellow-500/60'; // Amarelo
        if (t >= 6) return 'border-purple-500/60'; // Roxo
        if (t >= 5) return 'border-red-500/60'; // Vermelho
        if (t >= 4) return 'border-blue-500/60'; // Azul
        if (t >= 3) return 'border-green-500/60'; // Verde
        return 'border-slate-700'; // Cinza/Normal
    };

    const getFallbackIcon = () => {
        const id = itemId.toUpperCase();
        if (id.includes('SWORD') || id.includes('BOW') || id.includes('STAFF') || id.includes('AXE')) return <Sword className="w-6 h-6 opacity-20" />;
        if (id.includes('ARMOR') || id.includes('HELM') || id.includes('SHOES') || id.includes('SHIELD')) return <Shield className="w-6 h-6 opacity-20" />;
        return <Package className="w-6 h-6 opacity-20" />;
    };

    return (
        <div className={`relative flex items-center justify-center overflow-hidden bg-slate-900 rounded-lg border-2 ${getTierBorder(tier)} ${className}`}>

            {/* Overlay de Tier (Visual do jogo) */}
            <div className="absolute top-0 left-0 bg-black/40 px-1 rounded-br text-[8px] font-bold text-slate-300 z-20 pointer-events-none">
                T{tier}
            </div>

            {/* Skeleton / Loading */}
            {!loaded && !error && (
                <div className="absolute inset-0 bg-slate-800 animate-pulse flex items-center justify-center">
                    <div className="w-1/3 h-1/3 border-2 border-albion-gold/20 border-t-albion-gold rounded-full animate-spin"></div>
                </div>
            )}

            {/* Imagem Real */}
            {!error ? (
                <img 
                    src={imageUrl} 
                    alt={itemName}
                    className={`object-contain transition-all duration-300 z-10 p-0.5 ${loaded ? 'opacity-100 scale-100' : 'opacity-0 scale-90'} ${className}`}
                    onLoad={() => setLoaded(true)}
                    onError={() => { setError(true); setLoaded(true); }}
                    loading="lazy"
                />
            ) : (
                /* Fallback estilizado */
                <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-600 bg-slate-800 p-2">
                    {getFallbackIcon()}
                    <span className="text-[7px] uppercase font-black text-center leading-tight mt-1 opacity-50">
                        {itemName.split(' ').slice(0, 2).join(' ')}
                    </span>
                </div>
            )}

            {/* Brilho interno para parecer item 3D */}
            <div className="absolute inset-0 bg-gradient-to-tr from-black/20 to-white/5 pointer-events-none z-15"></div>
        </div>
    );
};

export default ItemImage;

import { MarketStat, ServerType, AlbionItem, Language } from '../types';
import { SERVER_URLS, CITIES, ITEM_DATABASE } from '../constants';
import { supabase } from './supabaseClient';

const CACHE_DURATION = 30 * 1000;
const memoryCache = new Map<string, { timestamp: number; data: any }>();

export const getItemImageUrl = (itemId: string, quality: number = 1): string => {
    const cleanId = itemId.split('@')[0];
    return `https://render.albiononline.com/v1/item/${itemId}.png?quality=${quality}`;
};

export const getRelativeTime = (dateString: string, t: Record<string, string>): string => {
    if (!dateString) return '';
    const date = new Date(dateString);
    if (isNaN(date.getTime())) return '';
    const now = new Date();
    const diffMs = now.getTime() - date.getTime(); 
    const diffMinutes = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMinutes / 60);
    const diffDays = Math.floor(diffHours / 24);
    if (diffMinutes < 1) return `< 1m ${t.ago || 'atrás'}`;
    if (diffMinutes < 60) return `${diffMinutes}m ${t.ago || 'atrás'}`;
    if (diffHours < 24) return `${diffHours}h ${t.ago || 'atrás'}`;
    return `${diffDays}d ${t.ago || 'atrás'}`;
};

// --- BUSCA INTELIGENTE (Fuzzy-like) ---
export const searchItems = async (
    searchTerm: string,
    category: string,
    tier: number | 'all',
    limit: number = 50,
    subcategory: string = 'all'
): Promise<AlbionItem[]> => {

    // Busca Local Otimizada (Multilíngue + ID + Tier)
    const query = searchTerm.toLowerCase().trim();
    const words = query.split(/\s+/);

    const results = ITEM_DATABASE.filter(item => {
        // 1. Filtro de Tier (via seletor)
        if (tier !== 'all' && item.tier !== tier) return false;

        // 2. Filtro de Categoria
        if (category !== 'all' && item.category.toLowerCase() !== category.toLowerCase()) return false;

        // 3. Filtro de Subcategoria
        if (subcategory !== 'all' && item.subcategory?.toLowerCase() !== subcategory.toLowerCase()) return false;

        // 4. Match Inteligente de Texto
        if (!query) return true;

        const searchableString = `
            ${item.names.en} 
            ${item.names.pt || ''} 
            ${item.names.es || ''} 
            ${item.id} 
            T${item.tier}
        `.toLowerCase();

        // Deve conter TODAS as palavras digitadas (ex: "espada adepto" busca itens com ambos os termos)
        return words.every(word => searchableString.includes(word));
    })
    .sort((a, b) => {
        // Prioridade 1: Match exato no início do nome em português ou inglês
        const aName = (a.names.pt || a.names.en).toLowerCase();
        const bName = (b.names.pt || b.names.en).toLowerCase();

        if (aName.startsWith(query) && !bName.startsWith(query)) return -1;
        if (!aName.startsWith(query) && bName.startsWith(query)) return 1;

        // Prioridade 2: Tier mais alto primeiro
        return b.tier - a.tier;
    });

    return results.slice(0, limit);
};

export const fetchMarketData = async (itemIds: string[], server: ServerType, forceUpdate: boolean = false): Promise<MarketStat[]> => {
    if (itemIds.length === 0) return [];
    const cacheKey = `prices:${server}:${itemIds.slice().sort().join(',')}`;
    const cached = memoryCache.get(cacheKey);
    if (!forceUpdate && cached && (Date.now() - cached.timestamp < CACHE_DURATION)) return cached.data;

    try {
        const baseUrl = SERVER_URLS[server]; 
        const url = `${baseUrl}/${itemIds.join(',')}?locations=Caerleon,Martlock,Thetford,Fort%20Sterling,Lymhurst,Bridgewatch,Brecilien&qualities=1,2,3,4,5`;
        const res = await fetch(url);
        if (!res.ok) throw new Error("API Error");
        const data = await res.json();
        memoryCache.set(cacheKey, { timestamp: Date.now(), data });
        return data;
    } catch (error) {
        return [];
    }
};

export const fetchGoldPrice = async (server: ServerType): Promise<MarketStat | null> => {
    try {
        const rootUrl = SERVER_URLS[server].split('/prices')[0];
        const res = await fetch(`${rootUrl}/gold?count=2`);
        if (!res.ok) return null;
        const data = await res.json();
        if (data.length > 0) {
            // ADP retorna array de preços históricos. Pegamos o mais recente e o anterior para média.
            return {
                item_id: 'GOLD',
                city: 'Global',
                quality: 1,
                sell_price_min: data[0].price,
                sell_price_min_date: data[0].timestamp,
                buy_price_max: data[1] ? (data[0].price + data[1].price) / 2 : data[0].price, // Média como fallback no buy_price
                buy_price_max_date: data[0].timestamp
            };
        }
        return null;
    } catch (e) { return null; }
};

export const fetchPriceHistory = async (itemId: string, server: ServerType, period: '24h' | '7d' | '30d'): Promise<any[]> => {
    const rootUrl = SERVER_URLS[server].split('/prices')[0];
    const date = new Date();
    if (period === '24h') date.setDate(date.getDate() - 1);
    else if (period === '7d') date.setDate(date.getDate() - 7);
    else date.setDate(date.getDate() - 30);

    const url = `${rootUrl}/charts/${itemId}?date=${date.toISOString().split('T')[0]}&time-scale=${period === '24h' ? 1 : 6}`;
    try {
        const res = await fetch(url);
        const data = await res.json();
        if (data[0]?.data) {
            return data[0].data.timestamps.map((t: any, i: number) => ({
                timestamp: new Date(t).toISOString(),
                price: data[0].data.prices_avg[i]
            }));
        }
        return [];
    } catch (e) { return []; }
};

export const getCraftableItems = async (): Promise<AlbionItem[]> => {
    return ITEM_DATABASE.filter(i => i.craftingRecipe);
};

