const App: React.FC = () => {
    const [user, setUser] = useState<User | null>(null);
    const [authChecking, setAuthChecking] = useState(true);
    const [language, setLanguage] = useState<Language>('en');
    const [selectedServer, setSelectedServer] = useState<ServerType>(ServerType.WEST);
    const [activeTab, setActiveTab] = useState('dashboard');
    const [activeCalculator, setActiveCalculator] = useState('crafting');
    const [viewingItemId, setViewingItemId] = useState<string | null>(null);
    const [sidebarOpen, setSidebarOpen] = useState(false);
    const [showPrivacyPolicy, setShowPrivacyPolicy] = useState(false);

    const { filters, updateFilter, resetFilters } = useMarketFilters();

    const [showAuthModal, setShowAuthModal] = useState(false);
    const [showSubscriptionModal, setShowSubscriptionModal] = useState(false);
    const [showProfileModal, setShowProfileModal] = useState(false);
    const [showBugReportModal, setShowBugReportModal] = useState(false);
    const [showSettingsModal, setShowSettingsModal] = useState(false);

    const [marketData, setMarketData] = useState<MarketStat[]>([]);
    const [loadingData, setLoadingData] = useState(false);
    const [searchedItems, setSearchedItems] = useState<AlbionItem[]>([]);
    const [isSearchingItems, setIsSearchingItems] = useState(false);

    const t = TRANSLATIONS[language];

    useEffect(() => {
        const initAuth = async () => {
            const currentUser = await authService.getCurrentUser();
            setUser(currentUser);
            setAuthChecking(false);
        };
        initAuth();
    }, []);

    const fetchData = useCallback(async (forceUpdate = false) => {
        if (!user) return;
        setLoadingData(true);
        try {
            const gold = await fetchGoldPrice(selectedServer);

            const itemIds = searchedItems.length > 0 
                ? searchedItems.map(i => i.id) 
                : ITEM_DATABASE.slice(0, 10).map(i => i.id);

            const prices = await fetchMarketData(itemIds, selectedServer, forceUpdate);

            const allData = [...prices];
            if (gold) allData.push(gold);

            setMarketData(allData);
        } catch (err) {
            console.error("Data fetch error", err);
        } finally {
            setLoadingData(false);
        }
    }, [user, selectedServer, searchedItems]);

    useEffect(() => {
        const performSearch = async () => {
            setIsSearchingItems(true);
            const results = await searchItems(filters.search, filters.category, filters.tier, 48, filters.subcategory);
            setSearchedItems(results);
            setIsSearchingItems(false);
        };
        const timeout = setTimeout(performSearch, 300);
        return () => clearTimeout(timeout);
    }, [filters]);

    useEffect(() => {
        fetchData();
        const interval = setInterval(() => fetchData(), 60000);
        return () => clearInterval(interval);
    }, [fetchData]);

    if (authChecking) return <div className="min-h-screen bg-[#0b1120] flex items-center justify-center"><Loader2 className="w-10 h-10 text-albion-gold animate-spin" /></div>;
    if (showPrivacyPolicy) return <PrivacyPolicy language={language} onBack={() => setShowPrivacyPolicy(false)} />;
    if (!user) return <><LandingPage onLogin={() => setShowAuthModal(true)} isLoggingIn={false} language={language} setLanguage={setLanguage} onPrivacyClick={() => setShowPrivacyPolicy(true)} />{showAuthModal && <AuthModal language={language} onClose={() => setShowAuthModal(false)} onAuthSuccess={setUser} />}</>;

    return (
        <div className="flex h-[100dvh] bg-[#0b1120] w-full overflow-hidden font-sans text-slate-200">
            {sidebarOpen && (
                <div className="fixed inset-0 z-[100] md:hidden">
                    <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setSidebarOpen(false)} />
                    <aside className="absolute top-0 bottom-0 left-0 w-72 bg-slate-900 border-r border-slate-700 p-4 overflow-y-auto">
                        <NavigationSidebar 
                            activeTab={activeTab} setActiveTab={setActiveTab}
                            activeCalculator={activeCalculator} setActiveCalculator={setActiveCalculator}
                            sidebarOpen={sidebarOpen} setSidebarOpen={setSidebarOpen}
                            setViewingItemId={setViewingItemId} language={language}
                            setShowSettingsModal={setShowSettingsModal} setShowBugReportModal={setShowBugReportModal}
                            handleLogout={() => authService.logout().then(() => setUser(null))}
                        />
                    </aside>
                </div>
            )}
            <aside className="hidden md:flex w-64 flex-col bg-slate-900 border-r border-slate-700 shrink-0 p-4">
                <NavigationSidebar 
                    activeTab={activeTab} setActiveTab={setActiveTab}
                    activeCalculator={activeCalculator} setActiveCalculator={setActiveCalculator}
                    sidebarOpen={sidebarOpen} setSidebarOpen={setSidebarOpen}
                    setViewingItemId={setViewingItemId} language={language}
                    setShowSettingsModal={setShowSettingsModal} setShowBugReportModal={setShowBugReportModal}
