            </aside>

            <div className="flex-1 flex flex-col min-w-0 h-full overflow-hidden bg-albion-dark">
                <header className="sticky top-0 z-40 bg-[#1e293b]/90 backdrop-blur-md border-b border-slate-700 flex-shrink-0 h-14 md:h-16 flex items-center justify-between px-4">
                    <button className="md:hidden p-2" onClick={() => setSidebarOpen(true)}><Menu className="w-6 h-6" /></button>
                    <div className="flex-1 text-center font-bold text-slate-300">
                        {activeTab === 'dashboard' ? t.dashboardTab : activeTab === 'items' ? t.findItemsTitle : t.calculatorTab}
                    </div>
                    <div className="flex items-center gap-3">
                        <button onClick={() => fetchData(true)} className="p-2 bg-slate-800 rounded-lg hover:bg-slate-700 transition-colors">
                            <RefreshCw className={`w-4 h-4 ${loadingData ? 'animate-spin' : ''}`} />
                        </button>
                        <img src={user.avatar} className="w-9 h-9 rounded-lg border border-slate-600" alt="Avatar" onClick={() => setShowProfileModal(true)} />
                    </div>
                </header>

                <main className="flex-1 overflow-y-auto p-4 sm:p-6 custom-scrollbar pb-24 md:pb-8">
                    <div className="max-w-7xl mx-auto w-full">
                        {viewingItemId ? (
