const generateItems = (): AlbionItem[] => {
    const items: AlbionItem[] = [];
    BASE_GEAR.forEach(base => {
        for (let tier = 4; tier <= 8; tier++) {
            const prefix = TIER_PREFIXES[tier];
            items.push({
                id: `T${tier}_${base.id}`,
                tier: tier,
                category: base.category,
                subcategory: base.subcategory,
                names: { 
                    en: `${prefix.en} ${base.names.en}`, 
                    es: `${base.names.es} ${prefix.es}`, 
                    pt: `${base.names.pt} ${prefix.pt}` 
                }
            });
        }
    });
    return items;
};

