const generateDatabase = (): AlbionItem[] => {
    const items: AlbionItem[] = [];

    // --- COMIDAS (FOOD) --- Incluindo Sopa de Repolho
    const foods = [
        { id: 'SOUP', names: { en: 'Soup', pt: 'Sopa', es: 'Sopa' }, tiers: [1, 3, 5], sub: 'food' },
        { id: 'STEW', names: { en: 'Stew', pt: 'Guisado', es: 'Guisado' }, tiers: [4, 6, 8], sub: 'food' },
        { id: 'OMELETTE', names: { en: 'Omelette', pt: 'Omelete', es: 'Tortilla' }, tiers: [3, 5, 7], sub: 'food' },
        { id: 'SALAD', names: { en: 'Salad', pt: 'Salada', es: 'Ensalada' }, tiers: [2, 4, 6], sub: 'food' },
    ];

    const foodMaterialPrefixes: Record<number, string> = {
        1: "CARROT", 2: "BEAN", 3: "WHEAT", 4: "CHICKEN", 5: "CABBAGE", 6: "MUTTON", 7: "PORK", 8: "BEEF"
    };

    foods.forEach(f => {
        f.tiers.forEach(t => {
            const material = foodMaterialPrefixes[t];
            items.push({
                id: `T${t}_MEAL_${f.id}`,
                tier: t,
                category: 'consumables',
                subcategory: f.sub,
                names: {
                    en: `${f.names.en} (${material})`,
                    pt: `${f.names.pt} de ${material === 'CABBAGE' ? 'Repolho' : material === 'WHEAT' ? 'Trigo' : material === 'MUTTON' ? 'Carneiro' : material === 'PORK' ? 'Porco' : material === 'BEEF' ? 'Carne' : material === 'CARROT' ? 'Cenoura' : 'Feijão'}`,
                    es: `${f.names.es} de ${material}`
                }
            });
        });
    });

    // --- POÇÕES ---
    const potions = [
        { id: 'HEAL', names: { en: 'Healing Potion', pt: 'Poção de Cura', es: 'Poción de Vida' }, tiers: [2, 4, 6] },
        { id: 'ENERGY', names: { en: 'Energy Potion', pt: 'Poção de Energia', es: 'Poción de Energía' }, tiers: [2, 4, 6] },
    ];

    potions.forEach(p => {
        p.tiers.forEach(t => {
            items.push({
                id: `T${t}_POTION_${p.id}`,
                tier: t,
                category: 'consumables',
                subcategory: 'potions',
                names: p.names
            });
        });
    });

    // --- EQUIPAMENTOS ---
    const gears = [
        { id: 'MAIN_SWORD', cat: 'weapons', sub: 'sword', names: { en: 'Broadsword', pt: 'Espada Larga', es: 'Espada Ancha' } },
        { id: '2H_BOW', cat: 'weapons', sub: 'bow', names: { en: 'Bow', pt: 'Arco', es: 'Arco' } },
        { id: 'ARMOR_PLATE_SET1', cat: 'armor', sub: 'chest_plate', names: { en: 'Soldier Armor', pt: 'Armadura de Soldado', es: 'Armadura de Soldado' } },
    ];

    gears.forEach(g => {
        for (let t = 4; t <= 8; t++) {
            items.push({
                id: `T${t}_${g.id}`,
                tier: t,
                category: g.cat,
                subcategory: g.sub,
                names: {
                    en: `${TIER_PREFIXES[t].en} ${g.names.en}`,
                    pt: `${g.names.pt} ${TIER_PREFIXES[t].pt}`,
                    es: `${g.names.es} ${TIER_PREFIXES[t].es}`
                }
            });
        }
    });

    return items;
};

