};

const generateFullDatabase = (): AlbionItem[] => {
    const items: AlbionItem[] = [];

    // --- RECURSOS REFINADOS (Ouro do jogo) ---
    const resources = [
        { id: 'METALBAR', names: { en: 'Metal Bar', pt: 'Barra de Metal', es: 'Barra de Metal' }, cat: 'resources', sub: 'bar' },
        { id: 'PLANKS', names: { en: 'Planks', pt: 'Tábuas', es: 'Tablones' }, cat: 'resources', sub: 'planks' },
        { id: 'LEATHER', names: { en: 'Leather', pt: 'Couro', es: 'Cuero' }, cat: 'resources', sub: 'leather' },
        { id: 'CLOTH', names: { en: 'Cloth', pt: 'Tecido', es: 'Tela' }, cat: 'resources', sub: 'cloth' },
        { id: 'STONEBLOCK', names: { en: 'Stone Block', pt: 'Bloco de Pedra', es: 'Bloque de Piedra' }, cat: 'resources', sub: 'stoneblock' },
    ];

    resources.forEach(res => {
        for (let t = 2; t <= 8; t++) {
            items.push({
                id: `T${t}_${res.id}`,
                tier: t,
                category: res.cat,
                subcategory: res.sub,
                names: {
                    en: `${TIER_PREFIXES[t].en} ${res.names.en}`,
                    pt: `${res.names.pt} ${TIER_PREFIXES[t].pt}`,
                    es: `${res.names.es} ${TIER_PREFIXES[t].es}`
                }
            });
        }
    });

    // --- CONSUMÍVEIS (Sopas, Guisados, Omeletes) ---
    const foods = [
        { id: 'MEAL_SOUP', names: { en: 'Soup', pt: 'Sopa', es: 'Sopa' }, tiers: [1, 3, 5] },
        { id: 'MEAL_STEW', names: { en: 'Stew', pt: 'Guisado', es: 'Guisado' }, tiers: [4, 6, 8] },
        { id: 'MEAL_OMELETTE', names: { en: 'Omelette', pt: 'Omelete', es: 'Tortilla' }, tiers: [3, 5, 7] },
    ];

    foods.forEach(f => {
        f.tiers.forEach(t => {
            items.push({
                id: `T${t}_${f.id}`,
                tier: t,
                category: 'consumables',
                subcategory: 'food',
                names: {
                    en: `${TIER_PREFIXES[t].en} ${f.names.en}`,
                    pt: `${f.names.pt} ${TIER_PREFIXES[t].pt}`,
                    es: `${f.names.es} ${TIER_PREFIXES[t].es}`
                }
            });
        });
    });

    // --- EQUIPAMENTOS POPULARES ---
    const gear = [
        { id: 'MAIN_SWORD', names: { en: 'Broadsword', pt: 'Espada Larga', es: 'Espada Ancha' }, cat: 'weapons', sub: 'sword' },
        { id: '2H_BOW', names: { en: 'Bow', pt: 'Arco', es: 'Arco' }, cat: 'weapons', sub: 'bow' },
        { id: 'ARMOR_PLATE_SET1', names: { en: 'Soldier Armor', pt: 'Armadura de Soldado', es: 'Armadura de Soldado' }, cat: 'armor', sub: 'chest_plate' },
    ];

    gear.forEach(g => {
        for (let t = 4; t <= 8; t++) {
            items.push({
                id: `T${t}_${g.id}`,
                tier: t,
                category: g.cat,
                subcategory: g.sub,
                names: {
                    en: `${TIER_PREFIXES[t].en} ${g.names.en}`,
                    pt: `${g.names.pt} ${TIER_PREFIXES[t].pt}`,
                    es: `${g.names.es} ${TIER_PREFIXES[t].es}`
                }
            });
        }
    });

    return items;
};

