export const getRelativeTime = (dateString: string, t: Record<string, string>): string => {
    if (!dateString) return '';
    const date = new Date(dateString);
    if (isNaN(date.getTime())) return '';
    const now = new Date();
    const diffMs = now.getTime() - date.getTime(); 
    const diffMinutes = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMinutes / 60);
    const diffDays = Math.floor(diffHours / 24);
    if (diffMinutes < 1) return `< 1m ${t.ago || 'atrás'}`;
    if (diffMinutes < 60) return `${diffMinutes}m ${t.ago || 'atrás'}`;
    if (diffHours < 24) return `${diffHours}h ${t.ago || 'atrás'}`;
    return `${diffDays}d ${t.ago || 'atrás'}`;
};

const normalize = (str: string) => {
    if (!str) return "";
    return str.normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "")
        .toLowerCase()
        .replace(/\b(de|do|da|dos|das|o|a|e)\b/g, "") // Remove preposições comuns em PT
        .trim();
};

export const searchItems = async (
    searchTerm: string,
    category: string,
    tier: number | 'all',
    limit: number = 50,
    subcategory: string = 'all'
): Promise<AlbionItem[]> => {
    const query = normalize(searchTerm);
    const queryParts = query.split(/\s+/).filter(p => p.length > 0);

    let results = ITEM_DATABASE.filter(item => {
        if (tier !== 'all' && item.tier !== tier) return false;
        if (category !== 'all' && item.category !== category) return false;
        if (subcategory !== 'all' && item.subcategory !== subcategory) return false;

        if (queryParts.length === 0) return true;

        const searchableText = normalize(`${item.names.en} ${item.names.pt} ${item.names.es} ${item.id} t${item.tier}`);
        return queryParts.every(part => searchableText.includes(part));
    })
    .sort((a, b) => b.tier - a.tier);

    // Itens úteis padrão caso vazio
    if (!searchTerm && category === 'all' && tier === 'all') {
        results = ITEM_DATABASE.filter(i => i.id.includes('METALBAR') || i.id.includes('MEAL') || i.tier >= 6).slice(0, limit);
    }

    return results.slice(0, limit);
};

export const fetchMarketData = async (itemIds: string[], server: ServerType, forceUpdate: boolean = false): Promise<MarketStat[]> => {
    if (itemIds.length === 0) return [];
    const cacheKey = `prices:${server}:${itemIds.slice().sort().join(',')}`;
    const cached = memoryCache.get(cacheKey);
    if (!forceUpdate && cached && (Date.now() - cached.timestamp < CACHE_DURATION)) return cached.data;

    try {
        const baseUrl = SERVER_URLS[server]; 
        const url = `${baseUrl}/${itemIds.join(',')}?locations=Caerleon,Martlock,Thetford,Fort%20Sterling,Lymhurst,Bridgewatch,Brecilien,Black%20Market&qualities=1,2,3,4,5`;
        const res = await fetch(url);
        if (!res.ok) throw new Error("API Error");
        const data = await res.json();
        memoryCache.set(cacheKey, { timestamp: Date.now(), data });
        return data;
    } catch (error) {
        return [];
    }
};

export const fetchGoldPrice = async (server: ServerType): Promise<MarketStat | null> => {
    try {
        const base = SERVER_URLS[server].split('/api/v2')[0];
        const res = await fetch(`${base}/api/v2/stats/gold?count=2`);
        if (!res.ok) return null;
        const data = await res.json();
        if (data && data.length > 0) {
            return {
                item_id: 'GOLD', city: 'Global', quality: 1,
                sell_price_min: data[0].price, sell_price_min_date: data[0].timestamp,
                buy_price_max: data[1] ? data[1].price : data[0].price,
                buy_price_max_date: data[0].timestamp
            };
        }
        return null;
    } catch (e) { return null; }
};

export const fetchPriceHistory = async (itemId: string, server: ServerType, period: '24h' | '7d' | '30d'): Promise<any[]> => {
    const base = SERVER_URLS[server].split('/api/v2')[0];
    const date = new Date();
    if (period === '24h') date.setDate(date.getDate() - 1);
    else if (period === '7d') date.setDate(date.getDate() - 7);
    else date.setDate(date.getDate() - 30);

    const url = `${base}/api/v2/stats/charts/${itemId}?date=${date.toISOString().split('T')[0]}&time-scale=${period === '24h' ? 1 : 6}`;
    try {
        const res = await fetch(url);
        const data = await res.json();
        if (data[0]?.data) {
            return data[0].data.timestamps.map((t: any, i: number) => ({
                timestamp: new Date(t).toISOString(),
                price: data[0].data.prices_avg[i]
            }));
        }
        return [];
    } catch (e) { return []; }
};

export const getCraftableItems = async (): Promise<AlbionItem[]> => {
    return ITEM_DATABASE.filter(i => i.id.includes('MEAL') || i.id.includes('POTION') || i.id.includes('MAIN_') || i.id.includes('2H_'));
};

import React, { useState, useMemo } from 'react';
import { Language, ServerType } from '../types';
import { TRANSLATIONS, ITEM_DATABASE, CITIES, CATEGORY_TRANSLATIONS } from '../constants';
import { fetchMarketData, getRelativeTime } from '../services/albionService';
import ItemImage from './ItemImage';
import { ArrowRight, RefreshCw, Truck, MapPin, Clock, TrendingUp, Info } from 'lucide-react';

interface TransportCalculatorProps {
    language: Language;
    isPremium: boolean;
    onUpgrade: () => void;
}

const TransportCalculator: React.FC<TransportCalculatorProps> = ({ language, isPremium, onUpgrade }) => {
    const t = TRANSLATIONS[language];

    const [fromCity, setFromCity] = useState<string>('Martlock');
    const [toCity, setToCity] = useState<string>('Caerleon');
    const [loading, setLoading] = useState(false);
    const [results, setResults] = useState<any[]>([]);
    const [hasSearched, setHasSearched] = useState(false);
    const [taxRate, setTaxRate] = useState<number>(isPremium ? 6.5 : 10.5);

    const formatSilver = (amount: number) => {
        return new Intl.NumberFormat('en-US').format(Math.round(amount));
    };

    const getCityColor = (name: string) => CITIES.find(c => c.name === name)?.color || 'text-white';

    const calculateArbitrage = async () => {
        if (fromCity === toCity) return;
        setLoading(true);
        setHasSearched(true);
        setResults([]);

        // Pegar itens mais rodados para arbitragem (recursos e equipamentos)
        const candidateItems = ITEM_DATABASE.filter(i => i.tier >= 4);
        const itemIds = candidateItems.map(i => i.id);

        const marketData = await fetchMarketData(itemIds, ServerType.WEST);

        const routes: any[] = [];
        const now = Date.now();

        candidateItems.forEach(item => {
            const stats = marketData.filter(d => d.item_id === item.id && d.quality === 1);

            const buyNode = stats.find(d => d.city === fromCity);
            const sellNode = stats.find(d => d.city === toCity);

            if (buyNode && sellNode && buyNode.sell_price_min > 0 && sellNode.sell_price_min > 0) {
                const buyPrice = buyNode.sell_price_min;
                const sellPrice = sellNode.sell_price_min;

                // Lucro = (Venda * (1 - Taxa)) - Compra
                const netRevenue = sellPrice * (1 - (taxRate / 100));
                const profit = netRevenue - buyPrice;
                const roi = (profit / buyPrice) * 100;

                if (profit > 0) {
                    routes.push({
                        item,
                        buyPrice,
                        buyDate: buyNode.sell_price_min_date,
                        sellPrice,
                        sellDate: sellNode.sell_price_min_date,
                        profit,
                        roi: roi.toFixed(1)
                    });
                }
            }
        });

        setResults(routes.sort((a, b) => b.profit - a.profit).slice(0, 30));
        setLoading(false);
    };

    return (
        <div className="max-w-6xl mx-auto animate-fade-in pb-20">
            <div className="text-center mb-10">
                <div className="inline-flex p-3 bg-albion-gold/10 rounded-full mb-4">
                    <Truck className="text-albion-gold w-10 h-10" />
                </div>
                <h2 className="text-4xl font-black text-white uppercase tracking-tighter">
                    {t.transportTitle}
                </h2>
                <p className="text-slate-400 mt-2 font-medium">Detecte oportunidades de compra e venda entre mercados.</p>
            </div>

            <div className="bg-slate-900/90 border border-slate-700 rounded-3xl p-8 shadow-2xl mb-10">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-center">

                    <div className="space-y-2">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                            <MapPin className="w-3 h-3" /> {t.from}
                        </label>
                        <select 
                            value={fromCity}
                            onChange={(e) => setFromCity(e.target.value)}
                            className="w-full bg-slate-800 border border-slate-600 rounded-2xl p-4 text-white font-black focus:border-albion-gold focus:outline-none"
                        >
                            {CITIES.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                        </select>
                    </div>

                    <div className="flex justify-center">
                        <div className="w-12 h-12 bg-slate-800 rounded-full flex items-center justify-center border border-slate-700 shadow-inner">
                            <ArrowRight className="text-albion-gold w-6 h-6" />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                            <MapPin className="w-3 h-3" /> {t.to}
                        </label>
                        <select 
                            value={toCity}
                            onChange={(e) => setToCity(e.target.value)}
                            className="w-full bg-slate-800 border border-slate-600 rounded-2xl p-4 text-white font-black focus:border-albion-gold focus:outline-none"
                        >
                            {CITIES.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                        </select>
                    </div>
                </div>

                <div className="mt-8 flex flex-col md:flex-row justify-between items-center gap-4">
                    <div className="flex items-center gap-4 bg-slate-800 p-2 px-4 rounded-xl border border-slate-700">
                        <span className="text-xs font-bold text-slate-400 uppercase">Taxa de Mercado:</span>
                        <input 
                            type="number" 
                            value={taxRate} 
                            onChange={(e) => setTaxRate(Number(e.target.value))}
                            className="w-16 bg-slate-900 border border-slate-600 rounded-lg p-1 text-center text-white font-bold"
                        />
                        <span className="text-white font-bold">%</span>
                    </div>

                    <button 
                        onClick={calculateArbitrage}
                        disabled={loading || fromCity === toCity}
                        className="w-full md:w-auto px-10 py-4 bg-albion-gold text-slate-900 font-black rounded-2xl hover:bg-yellow-400 transition-all flex items-center justify-center gap-3 shadow-xl disabled:opacity-50"
                    >
                        {loading ? <RefreshCw className="w-6 h-6 animate-spin" /> : <TrendingUp className="w-6 h-6" />}
                        {t.calculateProfit}
                    </button>
                </div>
            </div>

            {hasSearched && (
                <div className="space-y-6 animate-fade-in">
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {results.length > 0 ? results.map((route, idx) => (
                            <div key={idx} className="bg-slate-900 border border-slate-700 rounded-3xl p-6 hover:border-albion-gold transition-all group">
                                <div className="flex items-center gap-4 mb-6">
                                    <ItemImage itemId={route.item.id} itemName={route.item.names.en} className="w-16 h-16" />
                                    <div className="flex-1 min-w-0">
                                        <h3 className="text-lg font-black text-white truncate group-hover:text-albion-gold">
                                            {route.item.names[language] || route.item.names['en']}
                                        </h3>
                                        <div className="flex items-center gap-2">
                                            <span className="bg-slate-800 text-slate-400 px-2 py-0.5 rounded text-[10px] font-black border border-slate-700">T{route.item.tier}</span>
                                            <span className="text-[10px] text-slate-500 font-bold uppercase">{route.item.category}</span>
                                        </div>
                                    </div>
                                </div>

                                <div className="space-y-4">
                                    <div className="flex justify-between items-center bg-slate-800/50 p-3 rounded-2xl border border-slate-700">
                                        <div className="text-[10px] font-black text-slate-500 uppercase">Compra</div>
                                        <div className="text-right">
                                            <div className="text-white font-black">{formatSilver(route.buyPrice)}</div>
                                            <div className="text-[9px] text-slate-500">{fromCity}</div>
                                        </div>
                                    </div>
                                    <div className="flex justify-center">
                                        <ArrowRight className="text-slate-700 w-4 h-4" />
                                    </div>
                                    <div className="flex justify-between items-center bg-slate-800/50 p-3 rounded-2xl border border-slate-700">
                                        <div className="text-[10px] font-black text-slate-500 uppercase">Venda</div>
                                        <div className="text-right">
                                            <div className="text-white font-black">{formatSilver(route.sellPrice)}</div>
                                            <div className="text-[9px] text-slate-500">{toCity}</div>
                                        </div>
                                    </div>
                                </div>

                                <div className="mt-6 pt-6 border-t border-slate-800 flex justify-between items-end">
                                    <div>
                                        <div className="text-[10px] font-black text-slate-500 uppercase mb-1">Lucro Líquido</div>
                                        <div className="text-2xl font-black text-green-400 tracking-tighter">
                                            +{formatSilver(route.profit)}
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <div className="text-[10px] font-black text-slate-500 uppercase mb-1">Retorno</div>
                                        <div className="text-lg font-black text-blue-400">
                                            {route.roi}%
                                        </div>
                                    </div>
                                </div>
                            </div>
                        )) : (
                            <div className="col-span-full py-20 text-center">
                                <Info className="w-12 h-12 text-slate-700 mx-auto mb-4" />
                                <p className="text-slate-500 font-bold">Nenhuma rota lucrativa encontrada com os dados atuais.</p>
                            </div>
                        )}
                    </div>
                </div>
            )}
        </div>
    );
};

export default TransportCalculator;

