                                className="mt-auto w-full py-4 rounded-2xl border-2 border-dashed border-slate-700 text-slate-500 font-black text-xs uppercase tracking-widest hover:text-albion-gold hover:border-albion-gold transition-all flex items-center justify-center gap-2"
                            >
                                {t.viewFullMarket} <ArrowRight className="w-4 h-4" />
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

