import React, { useState, useMemo } from 'react';
import { Language, ServerType } from '../types';
import { TRANSLATIONS, ITEM_DATABASE, CITIES } from '../constants';
import { fetchMarketData, getRelativeTime } from '../services/albionService';
import ItemImage from './ItemImage';
import { ArrowRight, RefreshCw, Truck, MapPin, TrendingUp, Info, AlertTriangle, Search } from 'lucide-react';

interface TransportCalculatorProps {
    language: Language;
    isPremium: boolean;
    onUpgrade: () => void;
}

const TransportCalculator: React.FC<TransportCalculatorProps> = ({ language, isPremium, onUpgrade }) => {
    const t = TRANSLATIONS[language];

    const [fromCity, setFromCity] = useState<string>('Martlock');
    const [toCity, setToCity] = useState<string>('Caerleon');
    const [loading, setLoading] = useState(false);
    const [results, setResults] = useState<any[]>([]);
    const [hasSearched, setHasSearched] = useState(false);
    const [taxRate, setTaxRate] = useState<number>(isPremium ? 6.5 : 10.5);

    const formatSilver = (amount: number) => {
        return new Intl.NumberFormat('en-US').format(Math.round(amount));
    };

    const getCityColor = (name: string) => CITIES.find(c => c.name === name)?.color || 'text-white';

    const calculateArbitrage = async () => {
        if (fromCity === toCity) return;
        setLoading(true);
        setHasSearched(true);
        setResults([]);

        // Selecionar itens de alta liquidez e volume de transporte (Recursos T4-T8 e Acessórios)
        const candidateItems = ITEM_DATABASE.filter(i => i.tier >= 4);
        const itemIds = candidateItems.map(i => i.id);

        // Buscar dados de mercado (em produção, o server deveria ser dinâmico)
        const marketData = await fetchMarketData(itemIds, ServerType.WEST);

        const routes: any[] = [];
        const now = Date.now();
        const MAX_AGE_MS = 12 * 60 * 60 * 1000; // 12 horas de tolerância para transporte

        candidateItems.forEach(item => {
            const stats = marketData.filter(d => d.item_id === item.id && d.quality === 1);

            const buyNode = stats.find(d => d.city === fromCity);
            const sellNode = stats.find(d => d.city === toCity);

            if (buyNode && sellNode && buyNode.sell_price_min > 0 && sellNode.sell_price_min > 0) {
                const buyPrice = buyNode.sell_price_min;
                const sellPrice = sellNode.sell_price_min;

                // Lucro Líquido = (Venda * (1 - Taxas)) - Compra
                const netRevenue = sellPrice * (1 - (taxRate / 100));
                const profit = netRevenue - buyPrice;
                const roi = (profit / buyPrice) * 100;

                // Só mostrar se o lucro for positivo e acima de um ROI mínimo de segurança (ex: 2%)
                if (profit > 0 && roi > 1) {
                    routes.push({
                        item,
                        buyPrice,
                        buyDate: buyNode.sell_price_min_date,
                        sellPrice,
                        sellDate: sellNode.sell_price_min_date,
                        profit,
                        roi: roi.toFixed(1),
                        age: now - new Date(sellNode.sell_price_min_date).getTime()
                    });
                }
            }
        });

        // Ordenar por Lucro Absoluto e limitar aos TOP 25
        setResults(routes.sort((a, b) => b.profit - a.profit).slice(0, 25));
        setLoading(false);
    };

    return (
        <div className="max-w-6xl mx-auto animate-fade-in pb-20">
            <div className="text-center mb-10">
                <div className="inline-flex p-4 bg-albion-gold/10 rounded-full mb-4">
                    <Truck className="text-albion-gold w-12 h-12" />
                </div>
                <h2 className="text-4xl font-black text-white uppercase tracking-tighter">
                    {t.transportTitle}
                </h2>
                <p className="text-slate-400 mt-2 font-medium">Localize itens baratos para revenda imediata em outros mercados.</p>
            </div>

            <div className="bg-slate-900/90 border border-slate-700 rounded-3xl p-8 shadow-2xl mb-10">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-center">

                    <div className="space-y-2">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                            <MapPin className="w-3 h-3" /> {t.from}
                        </label>
                        <select 
                            value={fromCity}
                            onChange={(e) => setFromCity(e.target.value)}
                            className="w-full bg-slate-800 border border-slate-600 rounded-2xl p-4 text-white font-black text-lg focus:border-albion-gold focus:outline-none"
                        >
                            {CITIES.filter(c => c.id !== 'Global' && c.id !== 'Black Market').map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                        </select>
                    </div>

                    <div className="flex justify-center">
                        <div className="w-16 h-16 bg-slate-800 rounded-full flex items-center justify-center border border-slate-700 shadow-inner">
                            <ArrowRight className="text-albion-gold w-8 h-8" />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                            <MapPin className="w-3 h-3" /> {t.to}
                        </label>
                        <select 
                            value={toCity}
                            onChange={(e) => setToCity(e.target.value)}
                            className="w-full bg-slate-800 border border-slate-600 rounded-2xl p-4 text-white font-black text-lg focus:border-albion-gold focus:outline-none"
                        >
                            {CITIES.filter(c => c.id !== 'Global').map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                        </select>
                    </div>
                </div>

                <div className="mt-8 flex flex-col md:flex-row justify-between items-center gap-4">
                    <div className="flex items-center gap-4 bg-slate-800 p-3 px-6 rounded-2xl border border-slate-700">
                        <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Taxas de Mercado:</span>
                        <input 
                            type="number" 
                            value={taxRate} 
                            onChange={(e) => setTaxRate(Number(e.target.value))}
                            className="w-20 bg-slate-900 border border-slate-600 rounded-xl p-2 text-center text-white font-black"
                        />
                        <span className="text-white font-black">%</span>
                    </div>

                    <button 
                        onClick={calculateArbitrage}
                        disabled={loading || fromCity === toCity}
                        className="w-full md:w-auto px-12 py-5 bg-albion-gold text-slate-900 font-black text-lg rounded-2xl hover:bg-yellow-400 transition-all flex items-center justify-center gap-3 shadow-xl disabled:opacity-50"
                    >
                        {loading ? <RefreshCw className="w-7 h-7 animate-spin" /> : <Search className="w-7 h-7" />}
                        {t.calculateProfit}
                    </button>
                </div>
            </div>

            {hasSearched && (
                <div className="space-y-8 animate-fade-in">
                    <div className="flex items-center gap-3 text-amber-400 bg-amber-900/20 p-4 rounded-xl border border-amber-700/50 mb-6">
                        <AlertTriangle className="w-6 h-6 shrink-0" />
                        <p className="text-sm font-bold">Importante: Verifique o Volume de Venda (Liquidez) antes de comprar grandes quantidades.</p>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {results.length > 0 ? results.map((route, idx) => (
                            <div key={idx} className="bg-slate-900 border border-slate-700 rounded-3xl p-6 hover:border-albion-gold transition-all group shadow-xl">
                                <div className="flex items-center gap-4 mb-6">
                                    <ItemImage itemId={route.item.id} itemName={route.item.names.en} className="w-20 h-20 shadow-2xl" />
                                    <div className="flex-1 min-w-0">
                                        <h3 className="text-xl font-black text-white truncate group-hover:text-albion-gold transition-colors">
                                            {route.item.names[language] || route.item.names['en']}
                                        </h3>
                                        <div className="flex items-center gap-2 mt-1">
                                            <span className="bg-slate-800 text-slate-400 px-2 py-0.5 rounded text-[10px] font-black border border-slate-700 uppercase">T{route.item.tier}</span>
                                            <span className="text-[10px] text-slate-500 font-black uppercase tracking-widest">{route.item.category}</span>
                                        </div>
                                    </div>
                                </div>

                                <div className="space-y-3">
                                    <div className="flex justify-between items-center bg-slate-800/40 p-4 rounded-2xl border border-slate-700/50">
                                        <div className="text-[11px] font-black text-slate-500 uppercase tracking-widest">Compra</div>
                                        <div className="text-right">
                                            <div className="text-white font-black text-lg">{formatSilver(route.buyPrice)}</div>
                                            <div className={`text-[10px] font-bold ${getCityColor(fromCity)}`}>{fromCity}</div>
                                        </div>
                                    </div>

                                    <div className="flex justify-center -my-2 relative z-10">
                                        <div className="bg-slate-900 p-1 rounded-full border border-slate-700">
                                            <ArrowRight className="text-slate-600 w-4 h-4" />
                                        </div>
                                    </div>

                                    <div className="flex justify-between items-center bg-slate-800/40 p-4 rounded-2xl border border-slate-700/50">
                                        <div className="text-[11px] font-black text-slate-500 uppercase tracking-widest">Venda</div>
                                        <div className="text-right">
                                            <div className="text-white font-black text-lg">{formatSilver(route.sellPrice)}</div>
                                            <div className={`text-[10px] font-bold ${getCityColor(toCity)}`}>{toCity}</div>
                                        </div>
                                    </div>
                                </div>

                                <div className="mt-8 pt-6 border-t border-slate-800 flex justify-between items-end">
                                    <div>
                                        <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Lucro por Unidade</div>
                                        <div className={`text-3xl font-black ${route.profit > 10000 ? 'text-green-400' : 'text-blue-400'} tracking-tighter`}>
                                            +{formatSilver(route.profit)}
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">ROI</div>
                                        <div className={`text-xl font-black ${parseFloat(route.roi) > 20 ? 'text-green-400' : 'text-slate-100'}`}>
                                            {route.roi}%
                                        </div>
                                    </div>
                                </div>
                                <div className="mt-4 text-[9px] text-slate-600 flex items-center justify-end gap-1 font-bold">
                                    Último scan: {getRelativeTime(route.sellDate, t)}
                                </div>
                            </div>
                        )) : (
                            <div className="col-span-full py-20 text-center">
                                <Info className="w-16 h-16 text-slate-700 mx-auto mb-4" />
                                <p className="text-slate-500 font-black text-xl uppercase tracking-widest">Sem rotas lucrativas no momento. Tente outras cidades.</p>
                            </div>
                        )}
                    </div>
                </div>
            )}
        </div>
    );
};

