interface TransportCalculatorProps {
    language: Language;
    isPremium: boolean;
    onUpgrade: () => void;
}

const TransportCalculator: React.FC<TransportCalculatorProps> = ({ language, isPremium, onUpgrade }) => {
    const t = TRANSLATIONS[language];

    const [fromCity, setFromCity] = useState<string>('Martlock');
    const [toCity, setToCity] = useState<string>('Caerleon');
    const [loading, setLoading] = useState(false);
    const [results, setResults] = useState<any[]>([]);
    const [hasSearched, setHasSearched] = useState(false);
    const [taxRate, setTaxRate] = useState<number>(isPremium ? 6.5 : 10.5);

    const formatSilver = (amount: number) => {
        return new Intl.NumberFormat('en-US').format(Math.round(amount));
    };

    const getCityColor = (name: string) => CITIES.find(c => c.name === name)?.color || 'text-white';

    const calculateArbitrage = async () => {
        if (fromCity === toCity) return;
        setLoading(true);
        setHasSearched(true);
        setResults([]);

        // Itens de alta rotatividade para arbitragem
        const candidateItems = ITEM_DATABASE.filter(i => i.tier >= 4);
        const itemIds = candidateItems.map(i => i.id);

        const marketData = await fetchMarketData(itemIds, ServerType.WEST);

        const routes: any[] = [];
        const now = Date.now();

        candidateItems.forEach(item => {
            const stats = marketData.filter(d => d.item_id === item.id && d.quality === 1);

            const buyNode = stats.find(d => d.city === fromCity);
            const sellNode = stats.find(d => d.city === toCity);

            if (buyNode && sellNode && buyNode.sell_price_min > 0 && sellNode.sell_price_min > 0) {
                const buyPrice = buyNode.sell_price_min;
                const sellPrice = sellNode.sell_price_min;

                const netRevenue = sellPrice * (1 - (taxRate / 100));
                const profit = netRevenue - buyPrice;
                const roi = (profit / buyPrice) * 100;

                // Regras de Elite: Lucro > 1000 e dados de venda com menos de 12h
                const sellAge = now - new Date(sellNode.sell_price_min_date).getTime();

                if (profit > 500 && roi > 2) {
                    routes.push({
                        item,
                        buyPrice,
                        buyDate: buyNode.sell_price_min_date,
                        sellPrice,
                        sellDate: sellNode.sell_price_min_date,
                        profit,
                        roi: roi.toFixed(1),
                        isFresh: sellAge < 2 * 60 * 60 * 1000 // Menos de 2h é "Fresh"
                    });
                }
            }
        });

        setResults(routes.sort((a, b) => b.profit - a.profit).slice(0, 30));
        setLoading(false);
    };

    return (
        <div className="max-w-6xl mx-auto animate-fade-in pb-20">
            <div className="text-center mb-10">
                <div className="inline-flex p-4 bg-albion-gold/10 rounded-full mb-4">
                    <Truck className="text-albion-gold w-12 h-12" />
                </div>
                <h2 className="text-4xl font-black text-white uppercase tracking-tighter shadow-sm">
                    {t.transportTitle}
                </h2>
                <p className="text-slate-100 mt-2 font-bold opacity-80">Localize itens baratos para vender caro. Foco em Prata real.</p>
            </div>

            <div className="bg-slate-900 border border-slate-700 rounded-3xl p-8 shadow-2xl mb-10">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-center">

                    <div className="space-y-2">
                        <label className="text-xs font-black text-slate-100 uppercase tracking-widest flex items-center gap-2">
                            <MapPin className="w-3 h-3 text-albion-gold" /> {t.from}
                        </label>
                        <select 
                            value={fromCity}
                            onChange={(e) => setFromCity(e.target.value)}
                            className="w-full bg-slate-800 border-2 border-slate-700 rounded-2xl p-4 text-white font-black text-lg focus:border-albion-gold focus:outline-none transition-all"
                        >
                            {CITIES.filter(c => c.id !== 'Global' && c.id !== 'Black Market').map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                        </select>
                    </div>

                    <div className="flex justify-center">
                        <div className="w-16 h-16 bg-slate-800 rounded-full flex items-center justify-center border-2 border-slate-700 shadow-inner group">
                            <ArrowRight className="text-albion-gold w-8 h-8 group-hover:translate-x-1 transition-transform" />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className="text-xs font-black text-slate-100 uppercase tracking-widest flex items-center gap-2">
                            <MapPin className="w-3 h-3 text-albion-gold" /> {t.to}
                        </label>
                        <select 
                            value={toCity}
                            onChange={(e) => setToCity(e.target.value)}
                            className="w-full bg-slate-800 border-2 border-slate-700 rounded-2xl p-4 text-white font-black text-lg focus:border-albion-gold focus:outline-none transition-all"
                        >
                            {CITIES.filter(c => c.id !== 'Global').map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                        </select>
                    </div>
                </div>

                <div className="mt-8 flex flex-col md:flex-row justify-between items-center gap-4">
                    <div className="flex items-center gap-4 bg-slate-800 p-3 px-6 rounded-2xl border border-slate-700">
                        <span className="text-xs font-black text-slate-100 uppercase">Taxas do Mercado (%):</span>
                        <input 
                            type="number" 
                            value={taxRate} 
                            onChange={(e) => setTaxRate(Number(e.target.value))}
                            className="w-20 bg-slate-900 border border-slate-600 rounded-xl p-2 text-center text-white font-black"
                        />
                    </div>

                    <button 
                        onClick={calculateArbitrage}
                        disabled={loading || fromCity === toCity}
                        className="w-full md:w-auto px-12 py-5 bg-albion-gold text-slate-900 font-black text-xl rounded-2xl hover:bg-yellow-400 active:scale-95 transition-all flex items-center justify-center gap-3 shadow-xl disabled:opacity-50"
                    >
                        {loading ? <RefreshCw className="w-7 h-7 animate-spin" /> : <Search className="w-7 h-7" />}
                        {t.calculateProfit}
                    </button>
                </div>
            </div>

            {hasSearched && (
                <div className="space-y-8 animate-fade-in">
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {results.length > 0 ? results.map((route, idx) => (
                            <div key={idx} className="bg-slate-900 border-2 border-slate-700 rounded-3xl p-6 hover:border-albion-gold transition-all group shadow-xl relative overflow-hidden">
                                {route.isFresh && (
                                    <div className="absolute top-0 right-0 bg-green-500 text-slate-900 font-black text-[10px] px-3 py-1 rounded-bl-xl flex items-center gap-1">
                                        <Zap className="w-3 h-3 fill-slate-900" /> DADOS RECENTES
                                    </div>
                                )}

                                <div className="flex items-center gap-4 mb-6">
                                    <ItemImage itemId={route.item.id} itemName={route.item.names.en} className="w-20 h-20 shadow-2xl ring-2 ring-slate-800" />
                                    <div className="flex-1 min-w-0">
                                        <h3 className="text-xl font-black text-white truncate group-hover:text-albion-gold transition-colors uppercase leading-tight">
                                            {route.item.names[language] || route.item.names['en']}
                                        </h3>
                                        <div className="flex items-center gap-2 mt-1">
                                            <span className="bg-slate-800 text-slate-100 px-2 py-0.5 rounded text-[11px] font-black border border-slate-600">T{route.item.tier}</span>
                                            <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{route.item.category}</span>
                                        </div>
                                    </div>
                                </div>

                                <div className="space-y-3">
                                    <div className="flex justify-between items-center bg-slate-800/60 p-4 rounded-2xl border border-slate-700">
                                        <div className="text-[11px] font-black text-slate-400 uppercase">Preço Compra</div>
                                        <div className="text-right">
                                            <div className="text-white font-black text-lg">{formatSilver(route.buyPrice)}</div>
                                            <div className={`text-[10px] font-black ${getCityColor(fromCity)}`}>{fromCity}</div>
                                        </div>
                                    </div>

                                    <div className="flex justify-between items-center bg-slate-800/60 p-4 rounded-2xl border border-slate-700">
                                        <div className="text-[11px] font-black text-slate-400 uppercase">Preço Venda</div>
                                        <div className="text-right">
                                            <div className="text-white font-black text-lg">{formatSilver(route.sellPrice)}</div>
                                            <div className={`text-[10px] font-black ${getCityColor(toCity)}`}>{toCity}</div>
                                        </div>
                                    </div>
                                </div>

                                <div className="mt-8 pt-6 border-t border-slate-800 flex justify-between items-end">
                                    <div>
                                        <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Lucro Líquido</div>
                                        <div className={`text-3xl font-black ${parseFloat(route.roi) > 15 ? 'text-green-400' : 'text-blue-400'} tracking-tighter`}>
                                            +{formatSilver(route.profit)}
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Retorno</div>
                                        <div className="text-xl font-black text-slate-100 bg-slate-800 px-3 py-1 rounded-xl">
                                            {route.roi}%
                                        </div>
                                    </div>
                                </div>
                                <div className="mt-4 text-[10px] text-slate-500 flex items-center justify-end gap-1 font-black">
                                    Atualizado há: {getRelativeTime(route.sellDate, t)}
                                </div>
                            </div>
                        )) : (
                            <div className="col-span-full py-20 text-center">
                                <Info className="w-16 h-16 text-slate-700 mx-auto mb-4" />
                                <p className="text-slate-400 font-black text-xl uppercase tracking-widest">Sem oportunidades de alta margem agora.</p>
                            </div>
                        )}
                    </div>
                </div>
            )}
        </div>
    );
};

