const generateDatabase = (): AlbionItem[] => {
    const items: AlbionItem[] = [];
    const tiers = [2, 3, 4, 5, 6, 7, 8];
    const enchants = [0, 1, 2, 3, 4];

    const baseItems = [
        { id: 'METALBAR', cat: 'resources', sub: 'bar', names: { en: 'Metal Bar', pt: 'Barra de Metal', es: 'Lingote' } },
        { id: 'PLANKS', cat: 'resources', sub: 'planks', names: { en: 'Planks', pt: 'Tábuas', es: 'Tablones' } },
        { id: 'LEATHER', cat: 'resources', sub: 'leather', names: { en: 'Leather', pt: 'Couro', es: 'Cuero' } },
        { id: 'CLOTH', cat: 'resources', sub: 'cloth', names: { en: 'Cloth', pt: 'Tecido', es: 'Tela' } },
        { id: 'BAG', cat: 'accessories', sub: 'bag', names: { en: 'Bag', pt: 'Bolsa', es: 'Bolso' } },
        { id: 'CAPE', cat: 'accessories', sub: 'cape', names: { en: 'Cape', pt: 'Capa', es: 'Capa' } },
        { id: 'MAIN_SWORD', cat: 'weapons', sub: 'sword', names: { en: 'Sword', pt: 'Espada', es: 'Espada' } },
        { id: '2H_BOW', cat: 'weapons', sub: 'bow', names: { en: 'Bow', pt: 'Arco', es: 'Arco' } },
        { id: 'ARMOR_PLATE_SET1', cat: 'armor', sub: 'plate', names: { en: 'Soldier Armor', pt: 'Armadura de Soldado', es: 'Armadura de Soldado' } },
    ];

    baseItems.forEach(base => {
        tiers.forEach(t => {
            enchants.forEach(e => {
                if (e > 0 && t < 4) return; // Apenas T4+ tem encantamento
                const id = e > 0 ? `T${t}_${base.id}@${e}` : `T${t}_${base.id}`;
                items.push({
                    id,
                    tier: t,
                    category: base.cat,
                    subcategory: base.sub,
                    names: {
                        en: `T${t}${e > 0 ? '.'+e : ''} ${base.names.en}`,
                        pt: `${base.names.pt} T${t}${e > 0 ? '.'+e : ''}`,
                        es: `${base.names.es} T${t}${e > 0 ? '.'+e : ''}`
                    }
                });
            });
        });
    });

    return items;
};

