// --- Fix: Added missing fetchPriceHistory function ---
export const fetchPriceHistory = async (
    itemId: string, 
    server: ServerType, 
    period: '24h' | '7d' | '30d'
): Promise<{ timestamp: string; price: number }[]> => {
    try {
        const baseUrl = SERVER_URLS[server].split('/api/v2')[0];
        // Time scale: 1 = 24h (hourly), 24 = daily
        const timeScale = period === '24h' ? 1 : 24;
        // Fetching history from Caerleon as the primary market hub
        const url = `${baseUrl}/api/v2/stats/history/${itemId}?locations=Caerleon&time-scale=${timeScale}`;

        const res = await fetch(url);
        if (res.ok) {
            const data = await res.json();
            const history = data.length > 0 && data[0].data ? data[0].data : [];
            const limit = period === '24h' ? 24 : period === '7d' ? 7 : 30;
            return history.slice(-limit).map((d: any) => ({
                timestamp: d.timestamp,
                price: d.avg_price
            }));
        }
    } catch (e) {
        console.error("Error fetching price history:", e);
    }
    return [];
};

