    let filterEnchant = -1;
    let searchQuery = query;

    if (dotMatch) {
        filterTier = parseInt(dotMatch[1]);
        filterEnchant = parseInt(dotMatch[2]);
        searchQuery = query.replace(`${dotMatch[1]}.${dotMatch[2]}`, "").trim();
    } else {
        // Tenta achar apenas o tier: "couro 8"
        const tierMatch = query.match(/\b(t)?(\d)\b/);
        if (tierMatch) {
            filterTier = parseInt(tierMatch[2]);
            searchQuery = query.replace(tierMatch[0], "").trim();
        }
    }

    const queryWords = searchQuery.split(/\s+/).filter(w => w.length > 0);

    return ITEM_DATABASE.filter(item => {
        if (filterTier !== 'all' && item.tier !== filterTier) return false;
        if (category !== 'all' && item.category !== category) return false;
        if (subcategory !== 'all' && item.subcategory !== subcategory) return false;

        if (filterEnchant !== -1) {
            const hasEnchant = item.id.includes(`@${filterEnchant}`);
            if (filterEnchant === 0 && item.id.includes("@")) return false;
            if (filterEnchant > 0 && !hasEnchant) return false;
        }

        if (queryWords.length === 0) return true;

        const namesText = normalize(`${item.names.en} ${item.names.pt} ${item.names.es} ${item.id}`);
        return queryWords.every(word => namesText.includes(word));
    }).slice(0, limit);
};

export const fetchMarketData = async (itemIds: string[], server: ServerType, forceUpdate: boolean = false): Promise<MarketStat[]> => {
    if (itemIds.length === 0) return [];

    const chunkSize = 150;
    const allData: MarketStat[] = [];

    for (let i = 0; i < itemIds.length; i += chunkSize) {
        const chunk = itemIds.slice(i, i + chunkSize);
        const cacheKey = `prices:${server}:${chunk.join(',')}`;
        const cached = memoryCache.get(cacheKey);

        if (!forceUpdate && cached && (Date.now() - cached.timestamp < CACHE_DURATION)) {
            allData.push(...cached.data);
            continue;
        }

        try {
            const baseUrl = SERVER_URLS[server]; 
            const url = `${baseUrl}/${chunk.join(',')}?locations=Caerleon,Martlock,Thetford,Fort%20Sterling,Lymhurst,Bridgewatch,Brecilien,Black%20Market&qualities=1,2,3`;
            const res = await fetch(url);
            if (res.ok) {
                const data = await res.json();
                memoryCache.set(cacheKey, { timestamp: Date.now(), data });
                allData.push(...data);
            }
        } catch (e) {}
    }

    return allData;
};

export const fetchGoldPrice = async (server: ServerType): Promise<MarketStat | null> => {
    try {
        const base = SERVER_URLS[server].split('/api/v2')[0];
        const res = await fetch(`${base}/api/v2/stats/gold?count=1`);
        if (res.ok) {
            const data = await res.json();
            return {
                item_id: 'GOLD', city: 'Global', quality: 1,
                sell_price_min: data[0].price, sell_price_min_date: data[0].timestamp,
                buy_price_max: 0, buy_price_max_date: ''
            };
        }
        return null;
    } catch (e) { return null; }
};

export const getCraftableItems = async (): Promise<AlbionItem[]> => {
    return ITEM_DATABASE.filter(item => 
        ['weapons', 'armor', 'accessories'].includes(item.category)
    );
};

export const fetchPriceHistory = async (itemId: string, server: ServerType, period: '24h' | '7d' | '30d'): Promise<{ timestamp: string; price: number }[]> => {
    try {
        const baseUrl = SERVER_URLS[server].split('/api/v2')[0];
        const timeScale = period === '24h' ? 1 : 24;
        const url = `${baseUrl}/api/v2/stats/history/${itemId}?locations=Caerleon&time-scale=${timeScale}`;

        const res = await fetch(url);
        if (res.ok) {
            const data = await res.json();
            const history = data.length > 0 && data[0].data ? data[0].data : [];
            const limit = period === '24h' ? 24 : period === '7d' ? 7 : 30;
            return history.slice(-limit).map((d: any) => ({
                timestamp: d.timestamp,
                price: d.avg_price
            }));
        }
    } catch (e) {}
    return [];
};

import React, { useState } from 'react';
import { Language, ServerType } from '../types';
import { TRANSLATIONS, ITEM_DATABASE, CITIES } from '../constants';
import { fetchMarketData, getRelativeTime } from '../services/albionService';
import ItemImage from './ItemImage';
import { ArrowRight, RefreshCw, Truck, MapPin, TrendingUp, Info, Zap, Search } from 'lucide-react';

interface TransportCalculatorProps {
    language: Language;
    isPremium: boolean;
    onUpgrade: () => void;
}

const TransportCalculator: React.FC<TransportCalculatorProps> = ({ language, isPremium, onUpgrade }) => {
    const t = TRANSLATIONS[language];

    const [fromCity, setFromCity] = useState<string>('Martlock');
    const [toCity, setToCity] = useState<string>('Caerleon');
    const [loading, setLoading] = useState(false);
    const [results, setResults] = useState<any[]>([]);
    const [hasSearched, setHasSearched] = useState(false);
    const [taxRate, setTaxRate] = useState<number>(isPremium ? 6.5 : 10.5);

    const formatSilver = (amount: number) => {
        return new Intl.NumberFormat('en-US').format(Math.round(amount));
    };

    const getCityColor = (name: string) => CITIES.find(c => c.name === name)?.color || 'text-white';

    const calculateArbitrage = async () => {
        if (fromCity === toCity) return;
        setLoading(true);
        setHasSearched(true);
        setResults([]);

        // Foco em itens de alta liquidez: Recursos, Bolsas e Capas T4-T8
        const candidateItems = ITEM_DATABASE.filter(i => 
            (['resources', 'accessories'].includes(i.category)) && i.tier >= 4
        );

        const itemIds = candidateItems.map(i => i.id);
        const marketData = await fetchMarketData(itemIds, ServerType.WEST);

        const routes: any[] = [];
        const now = Date.now();

        candidateItems.forEach(item => {
            const stats = marketData.filter(d => d.item_id === item.id && d.quality === 1);

            const buyNode = stats.find(d => d.city === fromCity);
            const sellNode = stats.find(d => d.city === toCity);

            if (buyNode && sellNode && buyNode.sell_price_min > 0 && sellNode.sell_price_min > 0) {
                const buyPrice = buyNode.sell_price_min;
                const sellPrice = sellNode.sell_price_min;

                const netRevenue = sellPrice * (1 - (taxRate / 100));
                const profit = netRevenue - buyPrice;
                const roi = (profit / buyPrice) * 100;

                const sellAge = now - new Date(sellNode.sell_price_min_date).getTime();

                // Critérios de filtragem inteligente para trading real:
                if (profit > 1000 && roi > 2) {
                    routes.push({
                        item,
                        buyPrice,
                        sellPrice,
                        sellDate: sellNode.sell_price_min_date,
                        profit,
                        roi: roi.toFixed(1),
                        isFresh: sellAge < 2 * 60 * 60 * 1000 // Dados com menos de 2h
                    });
                }
            }
        });

        setResults(routes.sort((a, b) => b.profit - a.profit).slice(0, 30));
        setLoading(false);
    };

    return (
        <div className="max-w-6xl mx-auto animate-fade-in pb-20">
            <div className="text-center mb-10">
                <div className="inline-flex p-4 bg-albion-gold/10 rounded-full mb-4">
                    <Truck className="text-albion-gold w-12 h-12" />
                </div>
                <h2 className="text-4xl font-black text-white uppercase tracking-tighter text-glow-gold">
                    {t.transportTitle}
                </h2>
                <p className="text-slate-400 mt-2 font-medium">Localize as melhores rotas de comércio entre cidades reais.</p>
            </div>

            <div className="glass-panel rounded-3xl p-8 shadow-2xl mb-10 border-white/5">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-center">

                    <div className="space-y-3">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                            <MapPin className="w-3 h-3 text-albion-gold" /> {t.from}
                        </label>
                        <select 
                            value={fromCity}
                            onChange={(e) => setFromCity(e.target.value)}
                            className="w-full bg-slate-800/80 border border-slate-700 rounded-2xl p-4 text-white font-black text-lg focus:border-albion-gold focus:outline-none transition-all"
                        >
                            {CITIES.filter(c => c.id !== 'Global' && c.id !== 'Black Market').map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                        </select>
                    </div>

                    <div className="flex justify-center">
                        <div className="w-14 h-14 bg-slate-800 rounded-full flex items-center justify-center border border-white/10 shadow-inner group">
                            <ArrowRight className="text-albion-gold w-8 h-8 group-hover:translate-x-1 transition-transform" />
                        </div>
                    </div>

                    <div className="space-y-3">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                            <MapPin className="w-3 h-3 text-red-500" /> {t.to}
                        </label>
                        <select 
                            value={toCity}
                            onChange={(e) => setToCity(e.target.value)}
                            className="w-full bg-slate-800/80 border border-slate-700 rounded-2xl p-4 text-white font-black text-lg focus:border-albion-gold focus:outline-none transition-all"
                        >
                            {CITIES.filter(c => c.id !== 'Global').map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                        </select>
                    </div>
                </div>

                <div className="mt-8 flex flex-col md:flex-row justify-between items-center gap-6">
                    <div className="flex items-center gap-4 bg-slate-900/50 p-3 px-6 rounded-2xl border border-white/5">
                        <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">Taxas:</span>
                        <input 
                            type="number" 
                            value={taxRate} 
                            onChange={(e) => setTaxRate(Number(e.target.value))}
                            className="w-16 bg-transparent border-b border-slate-600 text-center text-white font-black focus:border-albion-gold outline-none"
                        />
                        <span className="text-white font-black">%</span>
                    </div>

                    <button 
                        onClick={calculateArbitrage}
                        disabled={loading || fromCity === toCity}
                        className="w-full md:w-auto px-12 py-5 bg-gradient-to-r from-albion-gold to-orange-500 text-albion-dark font-black text-lg rounded-2xl hover:scale-105 active:scale-95 transition-all flex items-center justify-center gap-3 shadow-[0_10px_25px_-5px_rgba(245,158,11,0.4)] disabled:opacity-50"
                    >
                        {loading ? <RefreshCw className="w-6 h-6 animate-spin" /> : <Search className="w-6 h-6" />}
                        {t.calculateProfit}
                    </button>
                </div>
            </div>

            {hasSearched && (
                <div className="space-y-6 animate-fade-in">
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {results.length > 0 ? results.map((route, idx) => (
                            <div key={idx} className="glass-panel border-white/5 rounded-3xl p-6 hover:border-albion-gold/50 transition-all group relative overflow-hidden">
                                {route.isFresh && (
                                    <div className="absolute top-0 right-0 bg-success text-white font-black text-[9px] px-3 py-1 rounded-bl-xl flex items-center gap-1 shadow-lg">
                                        <Zap className="w-3 h-3 fill-white" /> DADOS ATUAIS
                                    </div>
                                )}

                                <div className="flex items-center gap-4 mb-6">
                                    <ItemImage itemId={route.item.id} itemName={route.item.names.en} className="w-20 h-20 shadow-2xl rounded-xl ring-2 ring-white/5 group-hover:scale-110 transition-transform" />
                                    <div className="flex-1 min-w-0">
                                        <h3 className="text-xl font-serif font-black text-white truncate leading-tight">
                                            {route.item.names[language] || route.item.names['en']}
                                        </h3>
                                        <div className="flex items-center gap-2 mt-1">
                                            <span className="bg-slate-800 text-slate-400 px-2 py-0.5 rounded text-[10px] font-black border border-white/5">T{route.item.tier}</span>
                                            <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">{route.item.category}</span>
                                        </div>
                                    </div>
                                </div>

                                <div className="space-y-2">
                                    <div className="flex justify-between items-center bg-black/30 p-3 rounded-xl">
                                        <span className="text-[10px] font-black text-slate-500 uppercase">Compra</span>
                                        <span className="text-white font-black text-base">{formatSilver(route.buyPrice)} <span className={`text-[10px] font-bold ${getCityColor(fromCity)}`}>{fromCity}</span></span>
                                    </div>
                                    <div className="flex justify-between items-center bg-black/30 p-3 rounded-xl">
                                        <span className="text-[10px] font-black text-slate-500 uppercase">Venda</span>
                                        <span className="text-white font-black text-base">{formatSilver(route.sellPrice)} <span className={`text-[10px] font-bold ${getCityColor(toCity)}`}>{toCity}</span></span>
                                    </div>
                                </div>

                                <div className="mt-8 pt-6 border-t border-white/5 flex justify-between items-end">
                                    <div>
                                        <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">{t.profit}</div>
                                        <div className={`text-3xl font-black ${parseFloat(route.roi) > 15 ? 'text-success' : 'text-blue-400'} tracking-tighter text-glow-gold`}>
                                            +{formatSilver(route.profit)}
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">ROI</div>
                                        <div className="text-xl font-black text-slate-100 bg-white/5 px-3 py-1 rounded-xl">
                                            {route.roi}%
                                        </div>
                                    </div>
                                </div>
                                <div className="mt-4 text-[9px] text-slate-600 flex items-center justify-end gap-1 font-bold">
                                    Escaneado há {getRelativeTime(route.sellDate, t)}
                                </div>
                            </div>
                        )) : (
                            <div className="col-span-full py-20 text-center glass-panel rounded-3xl border-dashed">
                                <Info className="w-16 h-16 text-slate-700 mx-auto mb-4" />
                                <p className="text-slate-500 font-black text-xl uppercase tracking-widest">Sem rotas de alta rentabilidade encontradas. Tente mudar as cidades.</p>
                            </div>
                        )}
                    </div>
                </div>
            )}
        </div>
    );
};

