const generateDatabase = (): AlbionItem[] => {
    const items: AlbionItem[] = [];
    const tiers = [2, 3, 4, 5, 6, 7, 8];
    const enchants = [0, 1, 2, 3, 4];

    // --- RECURSOS REFINADOS ---
    const resources = [
        { id: 'METALBAR', cat: 'resources', sub: 'bar', names: { en: 'Metal Bar', pt: 'Barra de Metal', es: 'Lingote' } },
        { id: 'PLANKS', cat: 'resources', sub: 'planks', names: { en: 'Planks', pt: 'Tábuas', es: 'Tablones' } },
        { id: 'LEATHER', cat: 'resources', sub: 'leather', names: { en: 'Leather', pt: 'Couro', es: 'Cuero' } },
        { id: 'CLOTH', cat: 'resources', sub: 'cloth', names: { en: 'Cloth', pt: 'Tecido', es: 'Tela' } },
        { id: 'STONEBLOCK', cat: 'resources', sub: 'stone', names: { en: 'Stone Block', pt: 'Bloco de Pedra', es: 'Bloque' } },
    ];

    // --- EQUIPAMENTOS DE ALTA LIQUIDEZ ---
    const gear = [
        { id: 'BAG', cat: 'accessories', sub: 'bag', names: { en: 'Bag', pt: 'Bolsa', es: 'Bolso' } },
        { id: 'CAPE', cat: 'accessories', sub: 'cape', names: { en: 'Cape', pt: 'Capa', es: 'Capa' } },
        { id: 'MAIN_SWORD', cat: 'weapons', sub: 'sword', names: { en: 'Sword', pt: 'Espada', es: 'Espada' } },
        { id: 'ARMOR_PLATE_SET1', cat: 'armor', sub: 'plate', names: { en: 'Soldier Armor', pt: 'Armadura de Soldado', es: 'Armadura' } },
    ];

    // --- CONSUMÍVEIS (FLAT E ENCANTADOS) ---
    const consumables = [
        { id: 'MEAL_STEW', cat: 'consumables', sub: 'food', names: { en: 'Beef Stew', pt: 'Guisado de Carne', es: 'Guisado' } },
        { id: 'MEAL_OMELETTE', cat: 'consumables', sub: 'food', names: { en: 'Pork Omelette', pt: 'Omelete de Porco', es: 'Tortilla' } },
        { id: 'POTION_HEAL', cat: 'consumables', sub: 'potion', names: { en: 'Healing Potion', pt: 'Poção de Cura', es: 'Poción' } },
    ];

    // --- MONTARIAS ---
    const mounts = [
        { id: 'MOUNT_HORSE', cat: 'mounts', sub: 'horse', names: { en: 'Riding Horse', pt: 'Cavalo de Montaria', es: 'Caballo' } },
        { id: 'MOUNT_OX', cat: 'mounts', sub: 'ox', names: { en: 'Transport Ox', pt: 'Boi de Transporte', es: 'Buey' } },
    ];

    const allBase = [...resources, ...gear, ...consumables, ...mounts];

    allBase.forEach(base => {
        tiers.forEach(t => {
            enchants.forEach(e => {
                // Regras de validade do jogo
                if (e > 0 && t < 4) return; // Só T4+ tem encantamento
                if (base.cat === 'mounts' && e > 0) return; // Montarias básicas não tem encantamento
                if (base.id.includes('MEAL') && e > 3) return; // Comida vai até .3

                const id = e > 0 ? `T${t}_${base.id}@${e}` : `T${t}_${base.id}`;
                items.push({
                    id,
                    tier: t,
                    category: base.cat,
                    subcategory: base.sub,
                    names: {
                        en: `T${t}${e > 0 ? '.'+e : ''} ${base.names.en}`,
                        pt: `${base.names.pt} T${t}${e > 0 ? '.'+e : ''}`,
                        es: `${base.names.es} T${t}${e > 0 ? '.'+e : ''}`
                    }
                });
            });
        });
    });

    return items;
};

