import { MarketStat, ServerType, AlbionItem } from '../types';
import { SERVER_URLS, ITEM_DATABASE } from '../constants';

const CACHE_DURATION = 2 * 60 * 1000;
const memoryCache = new Map<string, { timestamp: number; data: any }>();

export const getItemImageUrl = (itemId: string, quality: number = 1): string => {
    return `https://render.albiononline.com/v1/item/${itemId}.png?quality=${quality}`;
};

export const getRelativeTime = (dateString: string, t: Record<string, string>): string => {
    if (!dateString) return '';
    const date = new Date(dateString);
    if (isNaN(date.getTime())) return '';
    const now = new Date();
    const diffMs = now.getTime() - date.getTime(); 
    const diffMinutes = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMinutes / 60);

    if (diffMinutes < 1) return `< 1m`;
    if (diffMinutes < 60) return `${diffMinutes}m`;
    if (diffHours < 24) return `${diffHours}h`;
    return `${Math.floor(diffHours/24)}d`;
};

// Normalização profissional de texto
const normalize = (str: string) => {
    return str.normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "") // Remove acentos
        .toLowerCase()
        .replace(/\b(de|do|da|dos|das|the|of|in|to)\b/g, "") // Remove conectores
        .replace(/\s+/g, " ")
        .trim();
};

export const searchItems = async (
    searchTerm: string,
    category: string,
    tier: number | 'all',
    limit: number = 60,
    subcategory: string = 'all'
): Promise<AlbionItem[]> => {
    const query = normalize(searchTerm);

    // Notação inteligente: "bolsa 4.1", "barra 8.3"
    const dotMatch = query.match(/(\d)\.(\d)/);
    let filterTier = tier;
    let filterEnchant = -1;
    let searchQuery = query;

    if (dotMatch) {
        filterTier = parseInt(dotMatch[1]);
        filterEnchant = parseInt(dotMatch[2]);
        searchQuery = query.replace(`${dotMatch[1]}.${dotMatch[2]}`, "").trim();
    } else {
        // Tenta achar "t8", "t4"
        const tierMatch = query.match(/\b(t)?(\d)\b/);
        if (tierMatch) {
            filterTier = parseInt(tierMatch[2]);
            searchQuery = query.replace(tierMatch[0], "").trim();
        }
    }

    const queryWords = normalize(searchQuery).split(/\s+/).filter(w => w.length > 0);

    return ITEM_DATABASE.filter(item => {
        if (filterTier !== 'all' && item.tier !== filterTier) return false;
        if (category !== 'all' && item.category !== category) return false;
        if (subcategory !== 'all' && item.subcategory !== subcategory) return false;

        if (filterEnchant !== -1) {
            const hasEnchant = item.id.includes(`@${filterEnchant}`);
            if (filterEnchant === 0 && item.id.includes("@")) return false;
            if (filterEnchant > 0 && !hasEnchant) return false;
        }

        if (queryWords.length === 0) return true;

        const namesText = normalize(`${item.names.en} ${item.names.pt} ${item.names.es} ${item.id}`);
        return queryWords.every(word => namesText.includes(word));
    }).slice(0, limit);
};

export const fetchMarketData = async (itemIds: string[], server: ServerType, forceUpdate: boolean = false): Promise<MarketStat[]> => {
    if (itemIds.length === 0) return [];

    const chunkSize = 150;
    const allData: MarketStat[] = [];

    for (let i = 0; i < itemIds.length; i += chunkSize) {
        const chunk = itemIds.slice(i, i + chunkSize);
        const cacheKey = `prices:${server}:${chunk.join(',')}`;
        const cached = memoryCache.get(cacheKey);

        if (!forceUpdate && cached && (Date.now() - cached.timestamp < CACHE_DURATION)) {
            allData.push(...cached.data);
            continue;
        }

        try {
            const baseUrl = SERVER_URLS[server]; 
            const url = `${baseUrl}/${chunk.join(',')}?locations=Caerleon,Martlock,Thetford,Fort%20Sterling,Lymhurst,Bridgewatch,Brecilien,Black%20Market&qualities=1,2,3`;
            const res = await fetch(url);
            if (res.ok) {
                const data = await res.json();
                memoryCache.set(cacheKey, { timestamp: Date.now(), data });
                allData.push(...data);
            }
        } catch (e) {}
    }

    return allData;
};

export const fetchGoldPrice = async (server: ServerType): Promise<MarketStat | null> => {
    try {
        const base = SERVER_URLS[server].split('/api/v2')[0];
        const res = await fetch(`${base}/api/v2/stats/gold?count=1`);
        if (res.ok) {
            const data = await res.json();
            return {
                item_id: 'GOLD', city: 'Global', quality: 1,
                sell_price_min: data[0].price, sell_price_min_date: data[0].timestamp,
                buy_price_max: 0, buy_price_max_date: ''
            };
        }
        return null;
    } catch (e) { return null; }
};

export const getCraftableItems = async (): Promise<AlbionItem[]> => {
    return ITEM_DATABASE.filter(item => 
        ['weapons', 'armor', 'accessories', 'consumables'].includes(item.category)
    );
};

export const fetchPriceHistory = async (itemId: string, server: ServerType, period: '24h' | '7d' | '30d'): Promise<{ timestamp: string; price: number }[]> => {
    try {
        const baseUrl = SERVER_URLS[server].split('/api/v2')[0];
        const timeScale = period === '24h' ? 1 : 24;
        const url = `${baseUrl}/api/v2/stats/history/${itemId}?locations=Caerleon&time-scale=${timeScale}`;

        const res = await fetch(url);
        if (res.ok) {
            const data = await res.json();
            const history = data.length > 0 && data[0].data ? data[0].data : [];
            const limit = period === '24h' ? 24 : period === '7d' ? 7 : 30;
            return history.slice(-limit).map((d: any) => ({
                timestamp: d.timestamp,
                price: d.avg_price
            }));
        }
    } catch (e) {}
    return [];
};

