    const items: AlbionItem[] = [];
    const tiers = [2, 3, 4, 5, 6, 7, 8];
    const enchants = [0, 1, 2, 3, 4];

    const allBase = [
        { id: 'METALBAR', cat: 'resources', names: { en: 'Metal Bar', pt: 'Barra de Metal', es: 'Lingote' } },
        { id: 'PLANKS', cat: 'resources', names: { en: 'Planks', pt: 'Tábuas', es: 'Tablones' } },
        { id: 'LEATHER', cat: 'resources', names: { en: 'Leather', pt: 'Couro', es: 'Cuero' } },
        { id: 'CLOTH', cat: 'resources', names: { en: 'Cloth', pt: 'Tecido', es: 'Tela' } },
        { id: 'BAG', cat: 'accessories', names: { en: 'Bag', pt: 'Bolsa', es: 'Bolso' } },
        { id: 'CAPE', cat: 'accessories', names: { en: 'Cape', pt: 'Capa', es: 'Capa' } },
        { id: 'MAIN_SWORD', cat: 'weapons', names: { en: 'Sword', pt: 'Espada', es: 'Espada' } },
        { id: 'MEAL_STEW', cat: 'consumables', names: { en: 'Beef Stew', pt: 'Guisado de Carne', es: 'Guisado' } },
        { id: 'MOUNT_OX', cat: 'mounts', names: { en: 'Transport Ox', pt: 'Boi de Transporte', es: 'Buey' } },
    ];

    allBase.forEach(base => {
        tiers.forEach(t => {
            enchants.forEach(e => {
                if (e > 0 && t < 4) return;
                const id = e > 0 ? `T${t}_${base.id}@${e}` : `T${t}_${base.id}`;
                items.push({
                    id, tier: t, category: base.cat,
                    names: {
                        en: `T${t}${e > 0 ? '.'+e : ''} ${base.names.en}`,
                        pt: `${base.names.pt} T${t}${e > 0 ? '.'+e : ''}`,
                        es: `${base.names.es} T${t}${e > 0 ? '.'+e : ''}`
                    }
                });
            });
        });
    });
    return items;
};

export const ITEM_DATABASE: AlbionItem[] = generateDatabase();

