import { MarketStat, ServerType, AlbionItem } from '../types';
import { SERVER_URLS, ITEM_DATABASE } from '../constants';

const CACHE_DURATION = 5 * 60 * 1000;
const memoryCache = new Map<string, { timestamp: number; data: any }>();

export const getItemImageUrl = (itemId: string, quality: number = 1): string => {
    return `https://render.albiononline.com/v1/item/${itemId}.png?quality=${quality}`;
};

export const getRelativeTime = (dateString: string, t: Record<string, string>): string => {
    if (!dateString) return '';
    const date = new Date(dateString);
    if (isNaN(date.getTime())) return '';
    const now = new Date();
    const diffMs = now.getTime() - date.getTime(); 
    const diffMinutes = Math.floor(diffMs / 60000);

    if (diffMinutes < 1) return `< 1m`;
    if (diffMinutes < 60) return `${diffMinutes}m`;
    const diffHours = Math.floor(diffMinutes / 60);
    if (diffHours < 24) return `${diffHours}h`;
    return `${Math.floor(diffHours/24)}d`;
};

const normalize = (str: string) => {
    return str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase()
        .replace(/\b(de|do|da|dos|das|o|a|os|as)\b/g, "").replace(/\s+/g, " ").trim();
};

export const searchItems = async (
    searchTerm: string,
    category: string,
    tier: number | 'all',
    limit: number = 48,
    subcategory: string = 'all'
): Promise<AlbionItem[]> => {
    const query = normalize(searchTerm);

    // Filtro inicial se nada for digitado
    if (!query && category === 'all' && tier === 'all') {
        return ITEM_DATABASE.slice(0, limit);
    }

    // Lógica Inteligente: Identificar Tiers e Encantamentos no texto
    // Ex: "Arco 4.2" -> Tier 4, Enchant 2
    let smartTier: number | 'all' = tier;
    let smartEnchant = -1;
    let cleanQuery = query;

    // Detectar Notação de Ponto (ex: 8.3)
    const dotMatch = query.match(/(\d)\.(\d)/);
    if (dotMatch) {
        smartTier = parseInt(dotMatch[1]);
        smartEnchant = parseInt(dotMatch[2]);
        cleanQuery = query.replace(`${dotMatch[1]}.${dotMatch[2]}`, "").trim();
    }

    // Detectar Notação de "T" (ex: T7)
    const tMatch = query.match(/t(\d)/);
    if (tMatch && smartTier === 'all') {
        smartTier = parseInt(tMatch[1]);
        cleanQuery = cleanQuery.replace(`t${tMatch[1]}`, "").trim();
    }

    const words = normalize(cleanQuery).split(/\s+/).filter(w => w.length > 0);

    return ITEM_DATABASE.filter(item => {
        // Filtros de hierarquia
        if (smartTier !== 'all' && item.tier !== smartTier) return false;
        if (category !== 'all' && item.category !== category) return false;
        if (subcategory !== 'all' && item.subcategory !== subcategory) return false;

        // Filtro de encantamento (baseado no ID pois o database mock é simples)
        if (smartEnchant !== -1) {
            const hasEnchant = item.id.includes(`@${smartEnchant}`);
            if (smartEnchant === 0 && item.id.includes("@")) return false;
            if (smartEnchant > 0 && !hasEnchant) return false;
        }

        // Busca por palavras nos nomes e IDs
        if (words.length === 0) return true;
        const searchableText = normalize(`${item.names.en} ${item.names.pt} ${item.id}`);
        return words.every(word => searchableText.includes(word));
    }).slice(0, limit);
};

export const fetchMarketData = async (itemIds: string[], server: ServerType, forceUpdate: boolean = false): Promise<MarketStat[]> => {
    if (itemIds.length === 0) return [];

    // Gerar cache key baseada nos itens e servidor
    const cacheKey = `${server}:${itemIds.sort().join(',')}`;
    const cached = memoryCache.get(cacheKey);

    if (!forceUpdate && cached && (Date.now() - cached.timestamp < CACHE_DURATION)) {
        return cached.data;
    }

    try {
        const url = `${SERVER_URLS[server]}/${itemIds.join(',')}?locations=Caerleon,Martlock,Thetford,Fort%20Sterling,Lymhurst,Bridgewatch,Brecilien,Black%20Market&qualities=1`;
        const res = await fetch(url);
        if (res.ok) {
            const data = await res.json();
            memoryCache.set(cacheKey, { timestamp: Date.now(), data });
            return data;
        }
    } catch (e) {
        console.error("Market API Error:", e);
    }
    return [];
};

export const fetchGoldPrice = async (server: ServerType): Promise<MarketStat | null> => {
    try {
        const base = SERVER_URLS[server].split('/api/v2')[0];
        const res = await fetch(`${base}/api/v2/stats/gold?count=1`);
        if (res.ok) {
            const data = await res.json();
            if (data && data.length > 0) {
                return {
                    item_id: 'GOLD', city: 'Global', quality: 1,
                    sell_price_min: data[0].price, sell_price_min_date: data[0].timestamp,
                    buy_price_max: 0, buy_price_max_date: ''
                };
            }
        }
    } catch (e) {}
    return null;
};

export const fetchPriceHistory = async (itemId: string, server: ServerType, period: '24h' | '7d' | '30d'): Promise<{ timestamp: string; price: number }[]> => {
    try {
        const baseUrl = SERVER_URLS[server].split('/api/v2')[0];
        const timeScale = period === '24h' ? 1 : 24;
        const res = await fetch(`${baseUrl}/api/v2/stats/history/${itemId}?locations=Caerleon&time-scale=${timeScale}`);
        if (res.ok) {
            const data = await res.json();
            if (data.length > 0 && data[0].data) {
                const history = data[0].data;
                const limit = period === '24h' ? 24 : period === '7d' ? 7 : 30;
                return history.slice(-limit).map((d: any) => ({ timestamp: d.timestamp, price: d.avg_price }));
            }
        }
    } catch (e) {}
    return [];
};

export const getCraftableItems = async (): Promise<AlbionItem[]> => {
    return ITEM_DATABASE.filter(item => ['weapons', 'accessories', 'consumables'].includes(item.category));
};

import React, { useState, useEffect, useCallback, lazy, Suspense } from 'react';
import { User, ServerType, Language, MarketStat, AlbionItem } from './types';
import { TRANSLATIONS, ITEM_DATABASE } from './constants';
import { authService } from './services/authService';
import { fetchMarketData, fetchGoldPrice, searchItems } from './services/albionService';
import { useMarketFilters } from './hooks/useMarketFilters';

import Dashboard from './components/Dashboard';
import ItemDetailsPage from './components/ItemDetailsPage';
import AuthModal from './components/AuthModal';
import SubscriptionModal from './components/SubscriptionModal';
import UserProfileModal from './components/UserProfileModal';
import BugReportModal from './components/BugReportModal';
import SettingsModal from './components/SettingsModal';
import ItemCard from './components/ItemCard';
import LandingPage from './components/LandingPage';
import NavigationSidebar from './components/NavigationSidebar';
import GuidesPage from './components/GuidesPage';
import AdvancedMarketFilters from './components/AdvancedMarketFilters';
import { Loader2, RefreshCw, Menu } from 'lucide-react';

const CraftingCalculator = lazy(() => import('./components/CraftingCalculator'));
const RefiningCalculator = lazy(() => import('./components/RefiningCalculator'));
const FarmingCalculator = lazy(() => import('./components/FarmingCalculator'));
const TransmutationCalculator = lazy(() => import('./components/TransmutationCalculator'));
const TransportCalculator = lazy(() => import('./components/TransportCalculator'));
const GoldCard = lazy(() => import('./components/GoldCard'));

const LoadingSpinner = () => (
    <div className="flex items-center justify-center w-full h-64">
        <Loader2 className="w-10 h-10 text-albion-gold animate-spin" />
    </div>
);

const App: React.FC = () => {
    const [user, setUser] = useState<User | null>(null);
    const [authChecking, setAuthChecking] = useState(true);
    const [language, setLanguage] = useState<Language>('pt');
    const [selectedServer, setSelectedServer] = useState<ServerType>(ServerType.WEST);
    const [activeTab, setActiveTab] = useState('dashboard');
    const [activeCalculator, setActiveCalculator] = useState('transport');
    const [viewingItemId, setViewingItemId] = useState<string | null>(null);
    const [sidebarOpen, setSidebarOpen] = useState(false);

    const { filters, updateFilter, resetFilters } = useMarketFilters();

    const [showAuthModal, setShowAuthModal] = useState(false);
    const [showSubscriptionModal, setShowSubscriptionModal] = useState(false);
    const [showProfileModal, setShowProfileModal] = useState(false);
    const [showBugReportModal, setShowBugReportModal] = useState(false);
    const [showSettingsModal, setShowSettingsModal] = useState(false);

    const [marketData, setMarketData] = useState<MarketStat[]>([]);
    const [loadingData, setLoadingData] = useState(false);
    const [searchedItems, setSearchedItems] = useState<AlbionItem[]>([]);
    const [isSearchingItems, setIsSearchingItems] = useState(false);

    const t = TRANSLATIONS[language];

    useEffect(() => {
        const initAuth = async () => {
            const currentUser = await authService.getCurrentUser();
            setUser(currentUser);
            setAuthChecking(false);
        };
        initAuth();
    }, []);

    const fetchData = useCallback(async (forceUpdate = false) => {
        if (!user) return;
        setLoadingData(true);
        try {
            const gold = await fetchGoldPrice(selectedServer);
            const currentItems = searchedItems.length > 0 ? searchedItems : ITEM_DATABASE.slice(0, 15);
            const prices = await fetchMarketData(currentItems.map(i => i.id), selectedServer, forceUpdate);
            const allData = [...prices];
            if (gold) allData.push(gold);
            setMarketData(allData);
        } catch (err) {
            console.error(err);
        } finally {
            setLoadingData(false);
        }
    }, [user, selectedServer, searchedItems]);

    useEffect(() => {
        const performSearch = async () => {
            setIsSearchingItems(true);
            const results = await searchItems(filters.search, filters.category, filters.tier, 48, filters.subcategory);
            setSearchedItems(results);
            setIsSearchingItems(false);
        };
        const timeout = setTimeout(performSearch, 400);
        return () => clearTimeout(timeout);
    }, [filters]);

    useEffect(() => {
        fetchData();
        const interval = setInterval(() => fetchData(), 120000);
        return () => clearInterval(interval);
    }, [fetchData]);

    if (authChecking) return <div className="min-h-screen bg-albion-dark flex items-center justify-center"><Loader2 className="w-10 h-10 text-albion-gold animate-spin" /></div>;
    if (!user) return <><LandingPage onLogin={() => setShowAuthModal(true)} isLoggingIn={false} language={language} setLanguage={setLanguage} onPrivacyClick={() => {}} />{showAuthModal && <AuthModal language={language} onClose={() => setShowAuthModal(false)} onAuthSuccess={setUser} />}</>;

    const getHeaderTitle = () => {
        if (activeTab === 'dashboard') return t.dashboardTab;
        if (activeTab === 'items') return t.findItemsTitle;
        if (activeTab === 'calculators') return t.calculatorTab;
        if (activeTab === 'guides') return t.guidesTitle;
        if (activeTab === 'gold') return t.goldPrice;
        return "";
    };

    return (
        <div className="flex h-screen bg-albion-dark overflow-hidden text-slate-200">
            {/* Mobile Sidebar */}
            {sidebarOpen && (
                <div className="fixed inset-0 z-[100] md:hidden">
                    <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setSidebarOpen(false)} />
                    <aside className="absolute top-0 bottom-0 left-0 w-72 bg-slate-900 border-r border-slate-800 p-4 overflow-y-auto">
                        <NavigationSidebar 
                            activeTab={activeTab} setActiveTab={setActiveTab}
                            activeCalculator={activeCalculator} setActiveCalculator={setActiveCalculator}
                            sidebarOpen={sidebarOpen} setSidebarOpen={setSidebarOpen}
                            setViewingItemId={setViewingItemId} language={language}
                            setShowSettingsModal={setShowSettingsModal} setShowBugReportModal={setShowBugReportModal}
                            handleLogout={() => authService.logout().then(() => setUser(null))}
                        />
                    </aside>
                </div>
            )}

            {/* Desktop Sidebar */}
            <aside className="hidden md:flex w-64 flex-col bg-slate-900 border-r border-slate-800 shrink-0 p-4">
                <NavigationSidebar 
                    activeTab={activeTab} setActiveTab={setActiveTab}
                    activeCalculator={activeCalculator} setActiveCalculator={setActiveCalculator}
                    sidebarOpen={sidebarOpen} setSidebarOpen={setSidebarOpen}
                    setViewingItemId={setViewingItemId} language={language}
                    setShowSettingsModal={setShowSettingsModal} setShowBugReportModal={setShowBugReportModal}
                    handleLogout={() => authService.logout().then(() => setUser(null))}
                />
            </aside>

            <div className="flex-1 flex flex-col min-w-0 h-full overflow-hidden">
                <header className="sticky top-0 z-40 bg-slate-900/90 backdrop-blur-md border-b border-white/5 flex-shrink-0 h-16 flex items-center justify-between px-6">
                    <button className="md:hidden p-2 text-slate-400" onClick={() => setSidebarOpen(true)}><Menu className="w-6 h-6" /></button>
                    <div className="flex-1 text-center font-serif font-black text-soft-white text-xl uppercase tracking-tighter">
                        {getHeaderTitle()}
                    </div>
                    <div className="flex items-center gap-3">
                        <button onClick={() => fetchData(true)} className="p-2 bg-white/5 rounded-lg hover:bg-white/10 transition-colors text-slate-400">
                            <RefreshCw className={`w-4 h-4 ${loadingData ? 'animate-spin' : ''}`} />
                        </button>
                        <img src={user.avatar} className="w-9 h-9 rounded-xl border border-white/10 cursor-pointer shadow-lg" alt="Avatar" onClick={() => setShowProfileModal(true)} />
                    </div>
                </header>

                <main className="flex-1 overflow-y-auto p-6 custom-scrollbar pb-24 md:pb-8">
                    <div className="max-w-7xl mx-auto w-full">
                        {viewingItemId ? (
                            <ItemDetailsPage 
                                item={ITEM_DATABASE.find(i => i.id === viewingItemId) || ITEM_DATABASE[0]} 
                                marketData={marketData} 
                                language={language} 
                                onBack={() => setViewingItemId(null)} 
                                user={user} 
                                onUpgrade={() => setShowSubscriptionModal(true)} 
                            />
                        ) : (
                            <>
                                {activeTab === 'dashboard' && <Dashboard user={user} language={language} marketData={marketData} goldPrice={marketData.find(d => d.item_id === 'GOLD')} onItemClick={setViewingItemId} selectedServer={selectedServer} onViewMarket={() => setActiveTab('items')} />}
                                {activeTab === 'items' && (
                                    <div className="space-y-8">
                                        <AdvancedMarketFilters language={language} filters={filters} onUpdateFilter={updateFilter} onReset={resetFilters} />
                                        {isSearchingItems ? <LoadingSpinner /> : (
                                            searchedItems.length > 0 ? (
                                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 animate-fade-in">
                                                    {searchedItems.map(item => (
                                                        <ItemCard key={item.id} item={item} marketData={marketData} language={language} onSetAlert={()=>{}} onRemoveAlert={()=>{}} onSaveNote={()=>{}} onClick={setViewingItemId} isPremium={user.isPremium} />
                                                    ))}
                                                </div>
                                            ) : <div className="text-center py-24 text-slate-500 font-bold uppercase tracking-widest">{t.noItemsFound}</div>
                                        )}
                                    </div>
                                )}
                                {activeTab === 'calculators' && (
                                    <Suspense fallback={<LoadingSpinner />}>
                                        <div className="space-y-6">
                                            {activeCalculator === 'transport' && <TransportCalculator language={language} isPremium={user.isPremium} onUpgrade={() => setShowSubscriptionModal(true)} />}
                                            {activeCalculator === 'crafting' && <CraftingCalculator language={language} server={selectedServer} isPremium={user.isPremium} onUpgrade={() => setShowSubscriptionModal(true)} />}
                                            {activeCalculator === 'refining' && <RefiningCalculator marketData={marketData} language={language} isPremium={user.isPremium} onUpgrade={() => setShowSubscriptionModal(true)} />}
                                            {activeCalculator === 'transmutation' && <TransmutationCalculator language={language} server={selectedServer} />}
                                            {activeCalculator === 'farming' && <FarmingCalculator marketData={marketData} language={language} isPremium={user.isPremium} onUpgrade={() => setShowSubscriptionModal(true)} />}
                                        </div>
                                    </Suspense>
                                )}
                                {activeTab === 'guides' && <GuidesPage language={language} />}
                                {activeTab === 'gold' && <div className="max-w-3xl mx-auto"><GoldCard marketStat={marketData.find(d => d.item_id === 'GOLD')} language={language} onSetAlert={()=>{}} onRemoveAlert={()=>{}} isPremium={user.isPremium} /></div>}
                            </>
                        )}
                    </div>
                </main>
            </div>

            {showSubscriptionModal && <SubscriptionModal language={language} onClose={() => setShowSubscriptionModal(false)} onSubscribe={async () => {}} />}
            {showSettingsModal && <SettingsModal language={language} setLanguage={setLanguage} selectedServer={selectedServer} setSelectedServer={setSelectedServer} onClose={() => setShowSettingsModal(false)} />}
            {showBugReportModal && <BugReportModal language={language} user={user} onClose={() => setShowBugReportModal(false)} />}
            {showProfileModal && <UserProfileModal user={user} language={language} onClose={() => setShowProfileModal(false)} onUpdateUser={(u) => setUser({...user, ...u})} onManageSubscription={() => {}} />}
        </div>
    );
};

export default App;

